"""
Parameterized generator for GH945_autogluon_3294.

Source PR:    https://github.com/autogluon/autogluon/pull/3294
Source Issue: N/A

Seed varies: renames 'align' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH945_autogluon_3294'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH945_autogluon_3294'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('align', 'align' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH945_autogluon_3294',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'autogluon/autogluon',
                "pr_number": 3294,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/autogluon/autogluon/pull/3294",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'core/src/autogluon/core/utils/utils.py': 'import logging\nimport math\nimport pickle\nimport time\nimport random\nimport sys\nfrom typing import Callable, List, Tuple\n\nimport numpy as np\nimport pandas as pd\nimport scipy.stats\nfrom numpy.typing import ArrayLike\nfrom pandas import DataFrame, Series\nfrom sklearn.model_selection import RepeatedKFold, RepeatedStratifiedKFold, LeaveOneGroupOut\nfrom sklearn.model_selection import train_test_split\n\nfrom autogluon.common.utils.resource_utils import ResourceManager\nfrom .miscs import warning_filter\nfrom ..constants import (\n    BINARY, LARGE_DATA_THRESHOLD, MULTICLASS, MULTICLASS_UPPER_LIMIT, QUANTILE,\n    REGRESS_THRESHOLD_LARGE_DATA, REGRESS_THRESHOLD_SMALL_DATA, REGRESSION, SOFTCLASS\n)\nfrom ..metrics import accuracy, root_mean_squared_error, pinball_loss, Scorer\n\nlogger = logging.getLogger(__name__)\n\n\nclass CVSplitter:\n    def __init__(self,\n                 splitter_cls=None,\n                 n_splits=5,\n                 n_repeats=1,\n                 random_state=0,\n                 stratified=False,\n                 groups=None):\n        self.n_splits = n_splits\n        self.n_repeats = n_repeats\n        self.random_state = random_state\n        self.stratified = stratified\n        self.groups = groups\n        if splitter_cls is None:\n            splitter_cls = self._get_splitter_cls()\n        self._splitter = self._get_splitter(splitter_cls)\n\n    def _get_splitter_cls(self):\n        if self.groups is not None:\n            num_groups = len(self.groups.unique())\n            if self.n_repeats != 1:\n                raise AssertionError(f\'n_repeats must be 1 when split groups are specified. (n_repeats={self.n_repeats})\')\n            self.n_splits = num_groups\n            splitter_cls = LeaveOneGroupOut\n            # pass\n        elif self.stratified:\n            splitter_cls = RepeatedStratifiedKFold\n        else:\n            splitter_cls = RepeatedKFold\n        return splitter_cls\n\n    def _get_splitter(self, splitter_cls):\n        if splitter_cls == LeaveOneGroupOut:\n            return splitter_cls()\n        elif splitter_cls in [RepeatedKFold, RepeatedStratifiedKFold]:\n            return splitter_cls(n_splits=self.n_splits, n_repeats=self.n_repeats, random_state=self.random_state)\n        else:\n            raise AssertionError(f\'{splitter_cls} is not supported as a valid `splitter_cls` input to CVSplitter.\')\n\n    def split(self, X, y):\n        if isinstance(self._splitter, RepeatedStratifiedKFold):\n            # FIXME: There is a bug in sklearn that causes an incorrect ValueError if performing stratification and all classes have fewer than n_splits samples.\n            #  This is hacked by adding a dummy class with n_splits samples, performing the kfold split, then removing the dummy samples from all resulting indices.\n            #  This is very inefficient and complicated and ideally should be fixed in sklearn.\n            with warning_filter():\n                try:\n                    out = [[train_index, test_index] for train_index, test_index in self._splitter.split(X, y)]\n                except:\n                    y_dummy = pd.concat([y, pd.Series([-1] * self.n_splits)], ignore_index=True)\n                    X_dummy = pd.concat([X, X.head(self.n_splits)], ignore_index=True)\n                    invalid_index = set(list(y_dummy.tail(self.n_splits).index))\n                    out = [[train_index, test_index] for train_index, test_index in self._splitter.split(X_dummy, y_dummy)]\n                    len_out = len(out)\n                    for i in range(len_out):\n                        train_index, test_index = out[i]\n                        out[i][0] = [index for index in train_index if index not in invalid_index]\n                        out[i][1] = [index for index in test_index if index not in invalid_index]\n            return out\n        else:\n            return [[train_index, test_index] for train_index, test_index in self._splitter.split(X, y, groups=self.groups)]\n\n\ndef setup_compute(nthreads_per_trial, ngpus_per_trial):\n    if nthreads_per_trial is None or nthreads_per_trial == \'all\':\n        nthreads_per_trial = ResourceManager.get_cpu_count()  # Use all of processing power / trial by default. To use just half: # int(np.floor(multiprocessing.cpu_count()/2))\n    if ngpus_per_trial is None:\n        ngpus_per_trial = 0  # do not use GPU by default\n    elif ngpus_per_trial == \'all\':\n        ngpus_per_trial = ResourceManager.get_gpu_count_all()\n    if not isinstance(nthreads_per_trial, int) and nthreads_per_trial != \'auto\':\n        raise ValueError(f\'nthreads_per_trial must be an integer or "auto": nthreads_per_trial = {nthreads_per_trial}\')\n    if not isinstance(ngpus_per_trial, int) and ngpus_per_trial != \'auto\':\n        raise ValueError(f\'ngpus_per_trial must be an integer or "auto": ngpus_per_trial = {ngpus_per_trial}\')\n    return nthreads_per_trial, ngpus_per_trial\n\n\ndef setup_trial_limits(time_limit, num_trials, hyperparameters):\n    """ Adjust default time limits / num_trials """\n    if num_trials is None:\n        if time_limit is None:\n            time_limit = 10 * 60  # run for 10min by default\n        time_limit /= float(len(hyperparameters))  # each model type gets half the available time\n        num_trials = 1000  # run up to 1000 trials (or as you can within the given time_limit)\n    elif time_limit is None:\n        time_limit = int(1e6)  # user only specified num_trials, so run all of them regardless of time_limit\n    else:\n        time_limit /= float(len(hyperparameters))  # each model type gets half the available time\n\n    if time_limit <= 10:  # threshold = 10sec, ie. too little time to run >1 trial.\n        num_trials = 1\n    time_limit *= 0.9  # reduce slightly to account for extra time overhead\n    return time_limit, num_trials\n\n\ndef get_leaderboard_pareto_frontier(leaderboard: DataFrame, score_col=\'score_val\', inference_time_col=\'pred_time_val_full\') -> DataFrame:\n    """\n    Given a set of models, returns in ranked order from best score to worst score models which satisfy the criteria:\n    1. No other model in the set has both a lower inference time and a better or equal score.\n\n    :param leaderboard: Leaderboard DataFrame of model info containing score_col and inference_time_col\n    :param score_col: Column name in leaderboard of model score values\n    :param inference_time_col: Column name in leaderboard of model inference times\n    :return: Subset of the original leaderboard DataFrame containing only models that are a valid optimal choice at different valuations of score and inference time.\n    """\n    leaderboard = leaderboard.sort_values(by=[score_col, inference_time_col], ascending=[False, True]).reset_index(drop=True)\n    leaderboard_unique = leaderboard.drop_duplicates(subset=[score_col])\n\n    pareto_frontier = []\n    inference_time_min = None\n    for index, row in leaderboard_unique.iterrows():\n        if row[inference_time_col] is None or row[score_col] is None:\n            pass\n        elif (inference_time_min is None) or (row[inference_time_col] < inference_time_min):\n            inference_time_min = row[inference_time_col]\n            pareto_frontier.append(index)\n    leaderboard_pareto_frontier = leaderboard_unique.loc[pareto_frontier].reset_index(drop=True)\n    return leaderboard_pareto_frontier\n\n\ndef shuffle_df_rows(X: DataFrame, seed=0, reset_index=True):\n    """Returns DataFrame with rows shuffled based on seed value."""\n    row_count = X.shape[0]\n    np.random.seed(seed)\n    rand_shuffle = np.random.randint(0, row_count, size=row_count)\n    X_shuffled = X.iloc[rand_shuffle]\n    if reset_index:\n        X_shuffled.reset_index(inplace=True, drop=True)\n    return X_shuffled\n\n\ndef normalize_binary_probas(y_predprob, eps):\n    """ Remaps the predicted probabilities to open interval (0,1) while maintaining rank order """\n    (pmin,pmax) = (eps, 1-eps)  # predicted probs outside this range will be remapped into (0,1)\n    which_toobig = y_predprob > pmax\n    if np.sum(which_toobig) > 0:  # remap overly large probs\n        y_predprob = np.logical_not(which_toobig)*y_predprob + which_toobig*(1-(eps*np.exp(-(y_predprob-pmax))))\n    which_toosmall = y_predprob < pmin\n    if np.sum(which_toosmall) > 0:  # remap overly small probs\n        y_predprob = np.logical_not(which_toosmall)*y_predprob + which_toosmall*eps*np.exp(-(pmin-y_predprob))\n    return y_predprob\n\n\ndef normalize_multi_probas(y_predprob, eps):\n    """ Remaps the predicted probabilities to lie in (0,1) where eps controls how far from 0 smallest class-probability lies """\n    min_predprob = np.min(y_predprob)\n    if min_predprob < 0:  # ensure nonnegative rows\n        most_negative_rowvals = np.clip(np.min(y_predprob, axis=1), a_min=None, a_max=0)\n        y_predprob = y_predprob - most_negative_rowvals[:,None]\n    if min_predprob < eps:\n        y_predprob = np.clip(y_predprob, a_min=eps, a_max=None)  # ensure no entries < eps\n        y_predprob = y_predprob / y_predprob.sum(axis=1, keepdims=1)  # renormalize\n    return y_predprob\n\n\ndef default_holdout_frac(num_train_rows, hyperparameter_tune=False):\n    """ Returns default holdout_frac used in fit().\n        Between row count 5,000 and 25,000 keep 0.1 holdout_frac, as we want to grow validation set to a stable 2500 examples.\n    """\n    if num_train_rows < 5000:\n        holdout_frac = max(0.1, min(0.2, 500.0 / num_train_rows))\n    else:\n        holdout_frac = max(0.01, min(0.1, 2500.0 / num_train_rows))\n\n    if hyperparameter_tune:\n        holdout_frac = min(0.2, holdout_frac * 2)  # We want to allocate more validation data for HPO to avoid overfitting\n\n    return holdout_frac\n\n\ndef augment_rare_classes(X, label, threshold):\n    """ Use this method when using certain eval_metrics like log_loss, for which no classes may be filtered out.\n        This method will augment dataset with additional examples of rare classes.\n    """\n    class_counts = X[label].value_counts()\n    class_counts_invalid = class_counts[class_counts < threshold]\n    if len(class_counts_invalid) == 0:\n        logger.debug("augment_rare_classes did not need to duplicate any data from rare classes")\n        return X\n\n    missing_classes = []\n    for clss, n_clss in class_counts_invalid.items():\n        if n_clss == 0:\n            missing_classes.append(clss)\n    if missing_classes:\n        logger.warning(f\'WARNING: {len(missing_classes)} classes were found that have 0 training examples, \'\n                       f\'and may lead to downstream issues. \'\n                       f\'Consider either providing data for these classes or removing them from the class categories. \'\n                       f\'These classes will be ignored: {missing_classes}\')\n        class_counts_invalid = class_counts_invalid[~class_counts_invalid.index.isin(set(missing_classes))]\n\n    if len(class_counts_invalid) == 0:\n        # This avoids crash when the only invalid classes were those that appeared 0 times\n        return X\n\n    aug_df = None\n    for clss, n_clss in class_counts_invalid.items():\n        n_toadd = threshold - n_clss\n        clss_df = X.loc[X[label] == clss]\n        if aug_df is None:\n            aug_df = clss_df[:0].copy()\n        duplicate_times = int(np.floor(n_toadd / n_clss))\n        remainder = n_toadd % n_clss\n        new_df = clss_df.copy()\n        new_df = new_df[:remainder]\n        while duplicate_times > 0:\n            logger.debug(f"Duplicating data from rare class: {clss}")\n            duplicate_times -= 1\n            new_df = pd.concat([new_df, clss_df], axis=0)\n        aug_df = pd.concat([aug_df, new_df], axis=0)\n\n    # Ensure new samples generated via augmentation have unique indices\n    aug_df = aug_df.reset_index(drop=True)\n    aug_df_len = len(aug_df)\n    X_index_aug_start = X.index.max() + 1\n    aug_index = [X_index_aug_start + i for i in range(aug_df_len)]\n    aug_df.index = aug_index\n\n    logger.log(20, f"Duplicated {len(aug_df)} samples from {len(class_counts_invalid)} rare classes in training set because eval_metric requires all classes have at least {threshold} samples.")\n\n    X = pd.concat([X, aug_df], axis=0)\n    class_counts = X[label].value_counts()\n    class_counts_invalid = class_counts[class_counts < threshold]\n    class_counts_invalid = class_counts_invalid[~class_counts_invalid.index.isin(set(missing_classes))]\n    if len(class_counts_invalid) > 0:\n        raise RuntimeError("augment_rare_classes failed to produce enough data from rare classes")\n    return X\n\n\ndef get_pred_from_proba_df(y_pred_proba, problem_type=BINARY):\n    """From input DataFrame of pred_proba, return Series of pred"""\n    if problem_type == REGRESSION:\n        y_pred = y_pred_proba\n    elif problem_type == QUANTILE:\n        y_pred = y_pred_proba\n    else:\n        y_pred = y_pred_proba.idxmax(axis=1)\n    return y_pred\n\n\ndef get_pred_from_proba(y_pred_proba, problem_type=BINARY):\n    if problem_type == BINARY:\n        # Using > instead of >= to align with Pandas `.idxmax` logic which picks the left-most column during ties.\n        # If this is not done, then predictions can be inconsistent when converting in binary classification from multiclass-form pred_proba and\n        # binary-form pred_proba when the pred_proba is 0.5 for positive and negative classes.\n        y_pred = [1 if pred > 0.5 else 0 for pred in y_pred_proba]\n    elif problem_type == REGRESSION:\n        y_pred = y_pred_proba\n    elif problem_type == QUANTILE:\n        y_pred = y_pred_proba\n    else:\n        y_pred = []\n        if not len(y_pred_proba) == 0:\n            y_pred = np.argmax(y_pred_proba, axis=1)\n    return y_pred\n\n\ndef convert_pred_probas_to_df(pred_proba_list: List[ArrayLike],\n                              columns: List[str],\n                              problem_type: str,\n                              index: pd.Index = None) -> DataFrame:\n    """\n    Converts a list of pred_proba model outputs to a DataFrame\n\n    Parameters\n    ----------\n    pred_proba_list : List[ArrayLike]\n        A list of prediction probabilities.\n        Each element is a numpy array or ndarray of prediction probabilities for a given model.\n    columns : List[str]\n        The column names for the output DataFrame\n    problem_type : str\n        The problem type. This informs the way in which the DataFrame is constructed.\n    index : pd.Index, default = None\n        If specified, sets the output DataFrame\'s index.\n\n    Returns\n    -------\n    DataFrame\n    """\n    if problem_type in [MULTICLASS, SOFTCLASS, QUANTILE]:\n        pred_proba_list = np.concatenate(pred_proba_list, axis=1)\n        pred_proba_df = pd.DataFrame(data=pred_proba_list, columns=columns)\n    else:\n        pred_proba_df = pd.DataFrame(data=np.asarray(pred_proba_list).T, columns=columns)\n    if index is not None:\n        pred_proba_df.set_index(index, inplace=True)\n    return pred_proba_df\n\n\ndef extract_label(data: DataFrame, label: str) -> (DataFrame, Series):\n    """\n    Extract the label column from a dataset and return X, y.\n\n    Parameters\n    ----------\n    data : DataFrame\n        The data containing features and the label column.\n    label : str\n        The label column name.\n\n    Returns\n    -------\n    X, y : (DataFrame, Series)\n        X is the data with the label column dropped.\n        y is the label column as a pd.Series.\n    """\n    if label not in list(data.columns):\n        raise ValueError(f"Provided DataFrame does not contain label column: {label}")\n    y = data[label].copy()\n    X = data.drop(label, axis=1)\n    return X, y\n\n\ndef generate_train_test_split_combined(data: DataFrame,\n                                       label: str,\n                                       problem_type: str,\n                                       test_size: float = 0.1,\n                                       random_state: int = 0,\n                                       min_cls_count_train: int = 1) -> (DataFrame, DataFrame):\n    """\n    Generate a train test split from a DataFrame that contains the label column.\n\n    Parameters\n    ----------\n    data : DataFrame\n        DataFrame containing the features plus the label column to split into train and test sets.\n    label : str\n        The label column name.\n        Used for stratification and to ensure all classes in multiclass classification are preserved in train data.\n    problem_type : str\n        The problem_type the label is used for. Determines if stratification is used.\n        Options: ["binary", "multiclass", "regression", "softclass", "quantile"]\n    test_size : float, default = 0.1\n        The proportion of data to use for the test set.\n        The remaining (1 - test_size) of data will be used for the training set.\n    random_state : int, default = 0\n        Random seed to use during the split.\n    min_cls_count_train : int, default = 1\n        The minimum number of instances of each class that must occur in the training set (for classification).\n        If not satisfied by the original split, instances of unsatisfied classes are\n        taken from test and put into train until satisfied.\n        Raises an exception if impossible to satisfy.\n\n    Returns\n    -------\n    train_data, test_data : (DataFrame, DataFrame)\n        The train_data and test_data after performing the split. Includes the label column.\n    """\n    X, y = extract_label(data=data, label=label)\n    train_data, test_data, y_train, y_test = generate_train_test_split(\n        X=X,\n        y=y,\n        problem_type=problem_type,\n        test_size=test_size,\n        random_state=random_state,\n        min_cls_count_train=min_cls_count_train)\n    train_data[label] = y_train\n    test_data[label] = y_test\n    return train_data, test_data\n\n\ndef generate_train_test_split(X: DataFrame,\n                              y: Series,\n                              problem_type: str,\n                              test_size: float = 0.1,\n                              random_state=0,\n                              min_cls_count_train=1) -> Tuple[DataFrame, DataFrame, Series, Series]:\n    """\n    Generate a train test split from input X, y.\n    If you have a combined X, y DataFrame, refer to `generate_train_test_split_combined` instead.\n\n    Parameters\n    ----------\n    X : DataFrame\n        pd.DataFrame containing the features minus the label column to split into train and test sets.\n    y : Series\n        pd.Series containing the label with matching indices to X.\n        Used for stratification and to ensure all classes in multiclass classification are preserved in train data.\n    problem_type : str\n        The problem_type the label is used for. Determines if stratification is used.\n        Options: ["binary", "multiclass", "regression", "softclass", "quantile"]\n    test_size : float, default = 0.1\n        The proportion of data to use for the test set.\n        The remaining (1 - test_size) of data will be used for the training set.\n    random_state : int, default = 0\n        Random seed to use during the split.\n    min_cls_count_train : int, default = 1\n        The minimum number of instances of each class that must occur in the training set (for classification).\n        If not satisfied by the original split, instances of unsatisfied classes are\n        taken from test and put into train until satisfied.\n        Raises an exception if impossible to satisfy.\n\n    Returns\n    -------\n    X_train, X_test, y_train, y_test : (DataFrame, DataFrame, Series, Series)\n        The train_data and test_data after performing the split, separated into X and y.\n\n    """\n    if (test_size <= 0.0) or (test_size >= 1.0):\n        raise ValueError("fraction of data to hold-out must be specified between 0 and 1")\n    valid_problem_types = [BINARY, MULTICLASS, REGRESSION, SOFTCLASS, QUANTILE]\n    assert problem_type in valid_problem_types, f\'Unknown problem type "{problem_type}" | Valid problem types: {valid_problem_types}\'\n\n    X_split = X\n    y_split = y\n    if problem_type in [BINARY, MULTICLASS]:\n        stratify = y\n    else:\n        stratify = None\n\n    # This code block is necessary to avoid crashing when performing a stratified split and only 1 sample exists for a class.\n    # This code will ensure that the sample will be part of the train split, meaning the test split will have 0 samples of the rare class.\n    rare_indices = None\n    if stratify is not None:\n        cls_counts = y.value_counts()\n        cls_counts_invalid = cls_counts[cls_counts < min_cls_count_train]\n\n        if len(cls_counts_invalid) > 0:\n            logger.error(f\'ERROR: Classes have too few samples to split the data! At least {min_cls_count_train} are required.\')\n            logger.error(cls_counts_invalid)\n            raise AssertionError(\'Not enough data to split data into train and val without dropping classes!\')\n        elif min_cls_count_train < 2:\n            cls_counts_rare = cls_counts[cls_counts < 2]\n            if len(cls_counts_rare) > 0:\n                cls_counts_rare_val = set(cls_counts_rare.index)\n                y_rare = y[y.isin(cls_counts_rare_val)]\n                rare_indices = list(y_rare.index)\n                X_split = X.drop(index=rare_indices)\n                y_split = y.drop(index=rare_indices)\n                stratify = y_split\n\n    X_train, X_test, y_train, y_test = train_test_split(X_split, y_split.values, test_size=test_size, shuffle=True, random_state=random_state, stratify=stratify)\n    if problem_type != SOFTCLASS:\n        y_train = pd.Series(y_train, index=X_train.index)\n        y_test = pd.Series(y_test, index=X_test.index)\n    else:\n        y_train = pd.DataFrame(y_train, index=X_train.index)\n        y_test = pd.DataFrame(y_test, index=X_test.index)\n\n    if rare_indices:\n        X_train = pd.concat([X_train, X.loc[rare_indices]])\n        y_train = pd.concat([y_train, y.loc[rare_indices]])\n\n    if problem_type in [BINARY, MULTICLASS]:\n        class_counts_dict_orig = y.value_counts().to_dict()\n        class_counts_dict = y_train.value_counts().to_dict()\n        class_counts_dict_test = y_test.value_counts().to_dict()\n\n        indices_to_move = []\n        random_state_init = random.getstate()\n        random.seed(random_state)\n        for cls in class_counts_dict_orig.keys():\n            count = class_counts_dict.get(cls, 0)\n            if count >= min_cls_count_train:\n                continue\n            count_test = class_counts_dict_test.get(cls, 0)\n            if count + count_test < min_cls_count_train:\n                raise AssertionError(\'Not enough data to split data into train and val without dropping classes!\')\n            count_to_move = min_cls_count_train - count\n            indices_of_cls_test = list(y_test[y_test == cls].index)\n            indices_to_move_cls = random.sample(indices_of_cls_test, count_to_move)\n            indices_to_move += indices_to_move_cls\n        random.setstate(random_state_init)\n        if indices_to_move:\n            y_test_moved = y_test.loc[indices_to_move].copy()\n            X_test_moved = X_test.loc[indices_to_move].copy()\n            y_train = pd.concat([y_train, y_test_moved])\n            X_train = pd.concat([X_train, X_test_moved])\n            y_test = y_test.drop(index=indices_to_move)\n            X_test = X_test.drop(index=indices_to_move)\n        y_train.name = y_split.name\n        y_test.name = y_split.name\n    return X_train, X_test, y_train, y_test\n\n\ndef normalize_pred_probas(y_predprob, problem_type, eps=1e-7):\n    """ Remaps the predicted probabilities to ensure there are no zeros (needed for certain metrics like log-loss)\n        and that no predicted probability exceeds [0,1] (eg. in distillation when classification is treated as regression).\n        Args:\n            y_predprob: 1D (for binary classification) or 2D (for multiclass) numpy array of predicted probabilities\n            problem_type: We only consider normalization if the problem_type is one of: [BINARY, MULTICLASS, SOFTCLASS]\n            eps: controls around how far from 0 remapped predicted probabilities should be (larger `eps` means predicted probabilities will lie further from 0).\n    """\n    if (problem_type == REGRESSION) and (len(y_predprob.shape) > 1) and (y_predprob.shape[1] > 1):\n        problem_type = SOFTCLASS  # this was MULTICLASS problem converted to REGRESSION (as done in distillation)\n\n    if problem_type in [BINARY, REGRESSION]:\n        if len(y_predprob.shape) > 1 and min(y_predprob.shape) > 1:\n            raise ValueError(f"cannot call normalize_pred_probas with problem_type={problem_type} and y_predprob.shape=={y_predprob.shape}")\n        return normalize_binary_probas(y_predprob, eps)\n    elif problem_type in [MULTICLASS, SOFTCLASS]:  # clip all probs below at eps and then renormalize\n        if len(y_predprob.shape) == 1:\n            return normalize_binary_probas(y_predprob, eps)\n        else:\n            return normalize_multi_probas(y_predprob, eps)\n    else:\n        raise ValueError(f"Invalid problem_type")\n\n\ndef infer_problem_type(y: Series, silent=False) -> str:\n    """ Identifies which type of prediction problem we are interested in (if user has not specified).\n        Ie. binary classification, multi-class classification, or regression.\n    """\n    with pd.option_context(\'mode.use_inf_as_na\', True): # treat None, NaN, INF, NINF as NA\n        y = y.dropna()\n    num_rows = len(y)\n\n    if num_rows == 0:\n        raise ValueError("Label column cannot have 0 valid values")\n\n    unique_values = y.unique()\n\n    if num_rows > LARGE_DATA_THRESHOLD:\n        regression_threshold = REGRESS_THRESHOLD_LARGE_DATA  # if the unique-ratio is less than this, we assume multiclass classification, even when labels are integers\n    else:\n        regression_threshold = REGRESS_THRESHOLD_SMALL_DATA\n\n    unique_count = len(unique_values)\n    if unique_count == 2:\n        problem_type = BINARY\n        reason = "only two unique label-values observed"\n    elif y.dtype.name in [\'object\', \'category\', \'string\']:\n        problem_type = MULTICLASS\n        reason = f"dtype of label-column == {y.dtype.name}"\n    elif np.issubdtype(y.dtype, np.floating):\n        unique_ratio = unique_count / float(num_rows)\n        if (unique_ratio <= regression_threshold) and (unique_count <= MULTICLASS_UPPER_LIMIT):\n            try:\n                can_convert_to_int = np.array_equal(y, y.astype(int))\n                if can_convert_to_int:\n                    problem_type = MULTICLASS\n                    reason = "dtype of label-column == float, but few unique label-values observed and label-values can be converted to int"\n                else:\n                    problem_type = REGRESSION\n                    reason = "dtype of label-column == float and label-values can\'t be converted to int"\n            except:\n                problem_type = REGRESSION\n                reason = "dtype of label-column == float and label-values can\'t be converted to int"\n        else:\n            problem_type = REGRESSION\n            reason = "dtype of label-column == float and many unique label-values observed"\n    elif np.issubdtype(y.dtype, np.integer):\n        unique_ratio = unique_count / float(num_rows)\n        if (unique_ratio <= regression_threshold) and (unique_count <= MULTICLASS_UPPER_LIMIT):\n            problem_type = MULTICLASS  # TODO: Check if integers are from 0 to n-1 for n unique values, if they have a wide spread, it could still be regression\n            reason = "dtype of label-column == int, but few unique label-values observed"\n        else:\n            problem_type = REGRESSION\n            reason = "dtype of label-column == int and many unique label-values observed"\n    else:\n        raise NotImplementedError(f\'label dtype {y.dtype} not supported!\')\n    if not silent:\n        logger.log(25, f"AutoGluon infers your prediction problem is: \'{problem_type}\' (because {reason}).")\n\n        # TODO: Move this outside of this function so it is visible even if problem type was not inferred.\n        if problem_type in [BINARY, MULTICLASS]:\n            if unique_count > 10:\n                logger.log(20, f\'\\tFirst 10 (of {unique_count}) unique label values:  {list(unique_values[:10])}\')\n            else:\n                logger.log(20, f\'\\t{unique_count} unique label values:  {list(unique_values)}\')\n        elif problem_type == REGRESSION:\n            y_max = y.max()\n            y_min = y.min()\n            y_mean = y.mean()\n            y_stddev = y.std()\n            logger.log(20, f\'\\tLabel info (max, min, mean, stddev): ({y_max}, {y_min}, {round(y_mean, 5)}, {round(y_stddev, 5)})\')\n\n        logger.log(25, f"\\tIf \'{problem_type}\' is not the correct problem_type, please manually specify the problem_type parameter during predictor init "\n                       f"(You may specify problem_type as one of: {[BINARY, MULTICLASS, REGRESSION]})")\n    return problem_type\n\n\ndef infer_eval_metric(problem_type: str) -> Scorer:\n    """Infers appropriate default eval metric based on problem_type. Useful when no eval_metric was provided."""\n    if problem_type == BINARY:\n        return accuracy\n    elif problem_type == MULTICLASS:\n        return accuracy\n    elif problem_type == QUANTILE:\n        return pinball_loss\n    else:\n        return root_mean_squared_error\n\n\ndef extract_column(X, col_name):\n    """Extract specified column from dataframe. """\n    if col_name is None or col_name not in list(X.columns):\n        return X, None\n    w = X[col_name].copy()\n    X = X.drop(col_name, axis=1)\n    return X, w\n\n\ndef compute_weighted_metric(y, y_pred, metric, weights, weight_evaluation=None, **kwargs):\n    """ Report weighted metric if: weights is not None, weight_evaluation=True, and the given metric supports sample weights.\n        If weight_evaluation=None, it will be set to False if weights=None, True otherwise.\n    """\n    if not metric.needs_quantile:\n        kwargs.pop(\'quantile_levels\', None)\n    if weight_evaluation is None:\n        weight_evaluation = not (weights is None)\n    if weight_evaluation and weights is None:\n        raise ValueError("Sample weights cannot be None when weight_evaluation=True.")\n    if not weight_evaluation:\n        return metric(y, y_pred, **kwargs)\n    try:\n        weighted_metric = metric(y, y_pred, sample_weight=weights, **kwargs)\n    except (ValueError, TypeError, KeyError):\n        if hasattr(metric, \'name\'):\n            metric_name = metric.name\n        else:\n            metric_name = metric\n        logger.log(30, f"WARNING: eval_metric=\'{metric_name}\' does not support sample weights so they will be ignored in reported metric.")\n        weighted_metric = metric(y, y_pred, **kwargs)\n    return weighted_metric\n\n\n# Note: Do not send training data as input or the importances will be overfit.\n# TODO: Improve time estimate (Currently pessimistic)\ndef compute_permutation_feature_importance(X: pd.DataFrame,\n                                           y: pd.Series,\n                                           predict_func: Callable[..., np.ndarray],\n                                           eval_metric: Scorer,\n                                           features: list = None,\n                                           subsample_size=None,\n                                           num_shuffle_sets: int = None,\n                                           predict_func_kwargs: dict = None,\n                                           transform_func: Callable[..., pd.DataFrame] = None,\n                                           transform_func_kwargs: dict = None,\n                                           time_limit: float = None,\n                                           silent=False,\n                                           log_prefix=\'\',\n                                           importance_as_list=False,\n                                           random_state=0,\n                                           **kwargs) -> pd.DataFrame:\n    """\n    Computes a trained model\'s feature importance via permutation shuffling (https://explained.ai/rf-importance/).\n    A feature\'s importance score represents the performance drop that results when the model makes predictions on a perturbed copy of the dataset where this feature\'s values have been randomly shuffled across rows.\n    A feature score of 0.01 would indicate that the predictive performance dropped by 0.01 when the feature was randomly shuffled.\n    The higher the score a feature has, the more important it is to the model\'s performance.\n    If a feature has a negative score, this means that the feature is likely harmful to the final model, and a model trained with the feature removed would be expected to achieve a better predictive performance.\n    Note that calculating feature importance can be a very computationally expensive process, particularly if the model uses hundreds or thousands of features. In many cases, this can take longer than the original model training.\n\n    Note: For highly accurate stddev and z_score estimates, it is recommend to set `subsample_size` to at least 5,000 if possible and `num_shuffle_sets` to at least 10.\n\n    Parameters\n    ----------\n    X : pd.DataFrame\n        Validation data to permute when calculating feature importances.\n        Do not use training data as it will result in overfit feature importances.\n    y : pd.Series\n        Label values of X. The index of X and y must align.\n    predict_func : Callable[..., np.ndarray]\n        Function that computes model predictions or prediction probabilities on input data.\n        Output must be in the form of a numpy ndarray or pandas Series or DataFrame.\n        Output `y_pred` must be in a form acceptable as input to `eval_metric(y, y_pred)`.\n        If using a fit model object, this is typically `model.predict` or `model.predict_proba`, depending on the `eval_metric` being used.\n        If `eval_metric.needs_pred==True`, use `model.predict`, otherwise use `model.predict_proba`.\n    eval_metric : Scorer\n        Object that computes a score given ground truth labels and predictions or prediction probabilities (depending on the type of metric).\n        If using a fit model object, this is typically `model.eval_metric`.\n        Feature importances will be based on the delta permutation shuffling has on the score produced by `eval_metric`.\n    features : list, default None\n        List of features to calculate importances for.\n        If None, all features\' importances will be calculated.\n        Can contain tuples as elements of (feature_name, feature_list) form.\n            feature_name can be any string so long as it is unique with all other feature names / features in the list.\n            feature_list can be any list of valid features in the data.\n            This will compute importance of the combination of features in feature_list, naming the set of features in the returned DataFrame feature_name.\n            This importance will differ from adding the individual importances of each feature in feature_list, and will be more accurate to the overall group importance.\n            Example: [\'featA\', \'featB\', \'featC\', (\'featBC\', [\'featB\', \'featC\'])]\n            In this example, the importance of \'featBC\' will be calculated by jointly permuting \'featB\' and \'featC\' together as if they were a single two-dimensional feature.\n    subsample_size : int, default None\n        The amount of data rows to sample when computing importances.\n        Higher values will improve the quality of feature importance estimates, but linearly increase the runtime.\n        If None, all provided data will be used.\n    num_shuffle_sets : int, default None\n        The number of different permutation shuffles of the data that are evaluated.\n        Shuffle sets are generated with different random seeds and importances are averaged across all shuffle sets to get the final feature importance values.\n        Higher values will improve the quality of feature importance estimates, but linearly increase the runtime.\n        `subsample_size` should be increased before `num_shuffle_sets` if runtime is a concern.\n        Defaults to 1 if `time_limit` is None or 10 if `time_limit` is specified.\n        When `num_shuffle_sets` is greater than 1, feature importance standard deviation and z-score will additionally be computed by using the results of each shuffle set as samples.\n    predict_func_kwargs : dict, default {}\n        Keyword arguments to be appended to calls to `predict_func(X, **kwargs)`.\n    transform_func : Callable[..., pd.DataFrame], default None\n        Transformation function that takes the raw input and transforms it row-wise to the input expected by `predict_func`.\n        Common examples include `model.preprocess` and `feature_generator.transform`.\n        If None, then no transformation is done on the data prior to calling `predict_func`.\n        This is necessary to compute importance of original data features in `X` prior to their transformation assuming `predict_func` does not perform the transformation already.\n            Example: `transform_func` is necessary to compute the importance of a text feature prior to being transformed into ngrams by `transform_func` when `predict_func` expects ngram features as input.\n    transform_func_kwargs : dict, default {}\n        Keyword arguments to be appended to calls to `transform_func(X, **kwargs)`.\n    time_limit : float, default None\n        Time in seconds to limit the calculation of feature importance.\n        If None, feature importance will calculate without early stopping.\n        A minimum of 1 full shuffle set will always be evaluated. If a shuffle set evaluation takes longer than `time_limit`, the method will take the length of a shuffle set evaluation to return regardless of the `time_limit`.\n        If `num_shuffle_sets==1`, `time_limit` will be ignored.\n    silent : bool, default False\n        Whether to suppress logging output.\n    log_prefix : str, default \'\'\n        Prefix to add to logging statements.\n    importance_as_list : bool, default False\n        Whether to return the \'importance\' column values as a list of the importance from each shuffle (True) or a single averaged value (False).\n    random_state : int, default 0\n        Acts as a seed for data subsampling and permuting feature values.\n\n    Returns\n    -------\n    Pandas `pandas.DataFrame` of feature importance scores with 4 columns:\n        index: The feature name.\n        \'importance\': The estimated feature importance score.\n        \'stddev\': The standard deviation of the feature importance score. If NaN, then not enough num_shuffle_sets were used to calculate a variance.\n        \'p_value\': P-value for a statistical t-test of the null hypothesis: importance = 0, vs the (one-sided) alternative: importance > 0.\n            Features with low p-value appear confidently useful to the predictor, while the other features may be useless to the predictor (or even harmful to include in its training data).\n            A p-value of 0.01 indicates that there is a 1% chance that the feature is useless or harmful, and a 99% chance that the feature is useful.\n            A p-value of 0.99 indicates that there is a 99% chance that the feature is useless or harmful, and a 1% chance that the feature is useful.\n        \'n\': The number of shuffles performed to estimate importance score (corresponds to sample-size used to determine confidence interval for true score).\n    """\n    if not eval_metric.needs_quantile:\n        kwargs.pop(\'quantile_levels\', None)\n\n    if num_shuffle_sets is None:\n        num_shuffle_sets = 1 if time_limit is None else 10\n\n    time_start = time.time()\n    if predict_func_kwargs is None:\n        predict_func_kwargs = dict()\n    if transform_func_kwargs is None:\n        transform_func_kwargs = dict()\n    if features is None:\n        features = list(X.columns)\n\n    _validate_features(features=features, valid_features=list(X.columns))\n\n    num_features = len(features)\n\n    if subsample_size is not None:\n        num_rows = min(len(X), subsample_size)\n    else:\n        num_rows = len(X)\n    subsample = num_rows < len(X)\n\n    if not silent:\n        logging_message = f\'{log_prefix}Computing feature importance via permutation shuffling for {num_features} features using {num_rows} rows with {num_shuffle_sets} shuffle sets...\'\n        if time_limit is not None:\n            logging_message = f\'{logging_message} Time limit: {time_limit}s...\'\n        logger.log(20, logging_message)\n\n    time_permutation_start = time.time()\n    fi_dict_list = []\n    shuffle_repeats_completed = 0\n    log_final_suffix = \'\'\n\n    X_orig = X\n    y_orig = y\n    feature_batch_count = None\n    X_raw = None\n    score_baseline = None\n    initial_random_state = random_state\n    # TODO: Can speedup shuffle_repeats by incorporating into X_raw (do multiple repeats in a single predict call)\n    for shuffle_repeat in range(num_shuffle_sets):\n        fi = dict()\n        random_state = initial_random_state + shuffle_repeat\n\n        if subsample:\n            # TODO: Stratify? We currently don\'t know in this function the problem_type (could pass as additional arg).\n            X = X_orig.sample(subsample_size, random_state=random_state)\n            y = y_orig.loc[X.index]\n\n        if subsample or shuffle_repeat == 0:\n            time_start_score = time.time()\n            X_transformed = X if transform_func is None else transform_func(X, **transform_func_kwargs)\n            y_pred = predict_func(X_transformed, **predict_func_kwargs)\n            score_baseline = eval_metric(y, y_pred, **kwargs)\n            if shuffle_repeat == 0:\n                if not silent:\n                    time_score = time.time() - time_start_score\n                    time_estimated = ((num_features + 1) * time_score) * num_shuffle_sets + time_start_score - time_start\n                    time_estimated_per_set = time_estimated / num_shuffle_sets\n                    logger.log(20, f\'{log_prefix}\\t{round(time_estimated, 2)}s\\t= Expected runtime ({round(time_estimated_per_set, 2)}s per shuffle set)\')\n\n                if transform_func is None:\n                    feature_batch_count = _get_safe_fi_batch_count(X=X, num_features=num_features)\n                else:\n                    feature_batch_count = _get_safe_fi_batch_count(X=X, num_features=num_features, X_transformed=X_transformed)\n\n            # creating copy of original data N=feature_batch_count times for parallel processing\n            X_raw = pd.concat([X.copy() for _ in range(feature_batch_count)], ignore_index=True, sort=False).reset_index(drop=True)\n\n        row_count = len(X)\n\n        X_shuffled = shuffle_df_rows(X=X, seed=random_state)\n\n        for i in range(0, num_features, feature_batch_count):\n            parallel_computed_features = features[i:i + feature_batch_count]\n\n            # if final iteration, leaving only necessary part of X_raw\n            num_features_processing = len(parallel_computed_features)\n            final_iteration = i + num_features_processing == num_features\n\n            row_index = 0\n            for feature in parallel_computed_features:\n                if isinstance(feature, tuple):\n                    feature = feature[1]\n                row_index_end = row_index + row_count\n                X_raw.loc[row_index:row_index_end - 1, feature] = X_shuffled[feature].values\n                row_index = row_index_end\n\n            if (num_features_processing < feature_batch_count) and final_iteration:\n                X_raw_transformed = X_raw.loc[:row_count * num_features_processing - 1]\n                X_raw_transformed = X_raw_transformed if transform_func is None else transform_func(X_raw_transformed, **transform_func_kwargs)\n            else:\n                X_raw_transformed = X_raw if transform_func is None else transform_func(X_raw, **transform_func_kwargs)\n            y_pred = predict_func(X_raw_transformed, **predict_func_kwargs)\n\n            row_index = 0\n            for feature in parallel_computed_features:\n                if isinstance(feature, tuple):\n                    feature_name = feature[0]\n                    feature_list = feature[1]\n                else:\n                    feature_name = feature\n                    feature_list = feature\n                # calculating importance score for given feature\n                row_index_end = row_index + row_count\n                y_pred_cur = y_pred[row_index:row_index_end]\n                score = eval_metric(y, y_pred_cur, **kwargs)\n                fi[feature_name] = score_baseline - score\n\n                # resetting to original values for processed feature\n                X_raw.loc[row_index:row_index_end - 1, feature_list] = X[feature_list].values\n\n                row_index = row_index_end\n        fi_dict_list.append(fi)\n        shuffle_repeats_completed = shuffle_repeat + 1\n        if time_limit is not None and shuffle_repeat != (num_shuffle_sets - 1):\n            time_now = time.time()\n            time_left = time_limit - (time_now - time_start)\n            time_permutation_average = (time_now - time_permutation_start) / (shuffle_repeat + 1)\n            if time_left < (time_permutation_average * 1.1):\n                log_final_suffix = \' (Early stopping due to lack of time...)\'\n                break\n\n    fi_list_dict = dict()\n    for val in fi_dict_list:\n        for key in val:\n            if key not in fi_list_dict:\n                fi_list_dict[key] = []\n            fi_list_dict[key].append(val[key])\n    fi_df = _compute_fi_with_stddev(fi_list_dict, importance_as_list=importance_as_list)\n\n    if not silent:\n        logger.log(20, f\'{log_prefix}\\t{round(time.time() - time_start, 2)}s\\t= Actual runtime (Completed {shuffle_repeats_completed} of {num_shuffle_sets} shuffle sets){log_final_suffix}\')\n\n    return fi_df\n\n\ndef _validate_features(features: list, valid_features: list):\n    """Raises exception if features list contains invalid features or duplicate features"""\n    valid_features = set(valid_features)\n    used_features = set()\n    # validate features\n    for feature in features:\n        if isinstance(feature, tuple):\n            feature_name = feature[0]\n            feature_list = feature[1]\n            feature_list_set = set(feature_list)\n            if len(feature_list_set) != len(feature_list):\n                raise ValueError(f\'Feature list contains duplicate features:\\n\'\n                                 f\'{feature_list}\')\n            for feature_in_list in feature_list:\n                if feature_in_list not in valid_features:\n                    raise ValueError(f\'Feature does not exist in data: {feature_in_list}\\n\'\n                                     f\'This feature came from the following feature set:\\n\'\n                                     f\'{feature}\\n\'\n                                     f\'Valid Features:\\n\'\n                                     f\'{valid_features}\')\n        else:\n            feature_name = feature\n            if feature_name not in valid_features:\n                raise ValueError(f\'Feature does not exist in data: {feature_name}\\n\'\n                                 f\'Valid Features:\\n\'\n                                 f\'{valid_features}\')\n        if feature_name in used_features:\n            raise ValueError(f\'Feature is present multiple times in feature list: {feature_name}\')\n        used_features.add(feature_name)\n\n\ndef _compute_fi_with_stddev(fi_list_dict: dict, importance_as_list=False) -> DataFrame:\n    features = list(fi_list_dict.keys())\n    fi = dict()\n    fi_stddev = dict()\n    fi_p_value = dict()\n    fi_n = dict()\n    for feature in features:\n        fi[feature], fi_stddev[feature], fi_p_value[feature], fi_n[feature] = _compute_mean_stddev_and_p_value(fi_list_dict[feature])\n        if importance_as_list:\n            fi[feature] = fi_list_dict[feature]\n\n    fi = pd.Series(fi).sort_values(ascending=False)\n    fi_stddev = pd.Series(fi_stddev)\n    fi_p_value = pd.Series(fi_p_value)\n    fi_n = pd.Series(fi_n, dtype=\'int64\')\n\n    fi_df = fi.to_frame(name=\'importance\')\n    fi_df[\'stddev\'] = fi_stddev\n    fi_df[\'p_value\'] = fi_p_value\n    fi_df[\'n\'] = fi_n\n    return fi_df\n\n\ndef _compute_mean_stddev_and_p_value(values: list):\n    mean = np.mean(values)\n    n = len(values)\n    p_value = np.nan\n    stddev = np.std(values, ddof=1) if n > 1 else np.nan\n    if stddev != np.nan and stddev != 0:\n        t_stat = mean / (stddev / math.sqrt(n))\n        p_value = scipy.stats.t.sf(t_stat, n-1)\n    elif stddev == 0:\n        p_value = 0.5\n\n    return mean, stddev, p_value, n\n\n\ndef _get_safe_fi_batch_count(X, num_features, X_transformed=None, max_memory_ratio=0.2, max_feature_batch_count=200):\n    # calculating maximum number of features that are safe to process in parallel\n    X_size_bytes = sys.getsizeof(pickle.dumps(X, protocol=4))\n    if X_transformed is not None:\n        X_size_bytes += sys.getsizeof(pickle.dumps(X_transformed, protocol=4))\n    available_mem = ResourceManager.get_available_virtual_mem()\n    X_memory_ratio = X_size_bytes / available_mem\n\n    feature_batch_count_safe = math.floor(max_memory_ratio / X_memory_ratio)\n    feature_batch_count = max(1, min(max_feature_batch_count, feature_batch_count_safe))\n    feature_batch_count = min(feature_batch_count, num_features)\n    return feature_batch_count\n\n\ndef unevaluated_fi_df_template(features: List[str]) -> pd.DataFrame:\n    importance_df = pd.DataFrame({\n        \'importance\': None,\n        \'stddev\': None,\n        \'p_value\': None,\n        \'n\': 0\n    }, index=features)\n    return importance_df\n',
            'tabular/src/autogluon/tabular/learner/abstract_learner.py': 'import copy\nimport json\nimport logging\nimport time\nfrom collections.abc import Iterable\n\nimport numpy as np\nimport pandas as pd\nfrom pandas import DataFrame, Series\nfrom typing import List\nfrom sklearn.metrics import classification_report\n\nfrom autogluon.core.constants import BINARY, MULTICLASS, REGRESSION, QUANTILE, AUTO_WEIGHT, BALANCE_WEIGHT\nfrom autogluon.core.data.label_cleaner import LabelCleaner, LabelCleanerMulticlassToBinary\nfrom autogluon.core.learner import AbstractLearner\nfrom autogluon.core.metrics import confusion_matrix, get_metric\nfrom autogluon.core.models.greedy_ensemble.ensemble_selection import EnsembleSelection\nfrom autogluon.core.utils import get_leaderboard_pareto_frontier, augment_rare_classes, extract_column, compute_weighted_metric\nfrom autogluon.core.utils import get_pred_from_proba, get_pred_from_proba_df, infer_problem_type\nfrom autogluon.features.generators import PipelineFeatureGenerator\n\nlogger = logging.getLogger(__name__)\n\n\n# TODO: - Semi-supervised learning\n# TODO: - Minimize memory usage of DataFrames (convert int64 -> uint8 when possible etc.)\n# Learner encompasses full problem, loading initial data, feature generation, model training, model prediction\n# TODO: Loading learner from S3 on Windows may cause issues due to os.path.sep\nclass AbstractTabularLearner(AbstractLearner):\n\n    def __init__(self, path_context: str, label: str, feature_generator: PipelineFeatureGenerator,\n                 ignored_columns: list = None, label_count_threshold=10, problem_type=None, quantile_levels=None,\n                 eval_metric=None, positive_class=None, cache_data=True, is_trainer_present=False, random_state=0,\n                 sample_weight=None, weight_evaluation=False, groups=None):\n        super().__init__(path_context=path_context, random_state=random_state)\n        self.label = label\n        self.ignored_columns = ignored_columns\n        if self.ignored_columns is None:\n            self.ignored_columns = []\n        self.threshold = label_count_threshold\n        self.problem_type = problem_type\n        self.eval_metric = get_metric(eval_metric, self.problem_type, \'eval_metric\')\n\n        if self.problem_type == QUANTILE and quantile_levels is None:\n            raise ValueError("if `problem_type=\'quantile\'`, `quantile_levels` has to be specified")\n        if isinstance(quantile_levels, float):\n            quantile_levels = [quantile_levels]\n        if isinstance(quantile_levels, Iterable):\n            for quantile in quantile_levels:\n                if quantile <= 0.0 or quantile >= 1.0:\n                    raise ValueError("quantile values have to be non-negative and less than 1.0 (0.0 < q < 1.0). "\n                                     "For example, 0.95 quantile = 95 percentile")\n            quantile_levels = np.sort(np.array(quantile_levels))\n        self.quantile_levels = quantile_levels\n\n        self.cache_data = cache_data\n        if not self.cache_data:\n            logger.log(30, \'Warning: `cache_data=False` will disable or limit advanced functionality after training such as feature importance calculations. It is recommended to set `cache_data=True` unless you explicitly wish to not have the data saved to disk.\')\n        self.is_trainer_present = is_trainer_present\n\n        self.cleaner = None\n        self.label_cleaner: LabelCleaner = None\n        self.feature_generator: PipelineFeatureGenerator = feature_generator\n\n        self._original_features = None\n        self._pre_X_rows = None\n        self._post_X_rows = None\n        self._positive_class = positive_class\n        self.sample_weight = sample_weight\n        self.weight_evaluation = weight_evaluation\n        self.groups = groups\n        if sample_weight is not None and not isinstance(sample_weight, str):\n            raise ValueError("sample_weight must be a string indicating the name of the column that contains sample weights. If you have a vector of sample weights, first add these as an extra column to your data.")\n        if weight_evaluation and sample_weight is None:\n            raise ValueError("Must specify sample_weight column if you specify weight_evaluation=True")\n        if groups is not None and not isinstance(groups, str):\n            raise ValueError(\'groups must be a string indicating the name of the column that contains the split groups. If you have a vector of split groups, first add these as an extra column to your data.\')\n\n    @property\n    def original_features(self) -> List[str]:\n        """Original features user passed in before autogluon doing any processing"""\n        return self._original_features\n\n    # TODO: Possibly rename to features_in or consider refactoring all feature_generators features_in -> features\n    @property\n    def features(self):\n        return self.feature_generator.features_in\n\n    @property\n    def feature_metadata_in(self):\n        return self.feature_generator.feature_metadata_in\n\n    @property\n    def feature_generators(self):\n        return [self.feature_generator]\n\n    @property\n    def class_labels(self):\n        return self.label_cleaner.ordered_class_labels\n\n    @property\n    def positive_class(self):\n        """\n        Returns the positive class name in binary classification. Useful for computing metrics such as F1 which require a positive and negative class.\n        In binary classification, :class:`TabularPredictor.predict_proba()` returns the estimated probability that each row belongs to the positive class.\n        Will print a warning and return None if called when `predictor.problem_type != \'binary\'`.\n\n        Returns\n        -------\n        The positive class name in binary classification or None if the problem is not binary classification.\n        """\n        if not self.is_fit:\n            if self._positive_class is not None:\n                return self._positive_class\n            raise AssertionError(\'Predictor must be fit to return positive_class.\')\n        if self.problem_type != BINARY:\n            logger.warning(f"Warning: Attempted to retrieve positive class label in a non-binary problem. Positive class labels only exist in binary classification. Returning None instead. self.problem_type is \'{self.problem_type}\' but positive_class only exists for \'{BINARY}\'.")\n            return None\n        return self.label_cleaner.cat_mappings_dependent_var[1]\n\n    def fit(self, X: DataFrame, X_val: DataFrame = None, **kwargs):\n        if self.is_fit:\n            raise AssertionError(\'Learner is already fit.\')\n        self._validate_fit_input(X=X, X_val=X_val, **kwargs)\n        return self._fit(X=X, X_val=X_val, **kwargs)\n\n    def _fit(self, X: DataFrame, X_val: DataFrame = None, scheduler_options=None, hyperparameter_tune=False,\n             feature_prune=False, holdout_frac=0.1, hyperparameters=None, verbosity=2):\n        raise NotImplementedError\n\n    def predict_proba(self, X: DataFrame, model=None, as_pandas=True, as_multiclass=True, inverse_transform=True, transform_features=True):\n        if as_pandas:\n            X_index = copy.deepcopy(X.index)\n        else:\n            X_index = None\n        if X.empty:\n            y_pred_proba = np.array([])\n        else:\n            if transform_features:\n                X = self.transform_features(X)\n            y_pred_proba = self.load_trainer().predict_proba(X, model=model)\n        if inverse_transform:\n            y_pred_proba = self.label_cleaner.inverse_transform_proba(y_pred_proba)\n        if as_multiclass and (self.problem_type == BINARY):\n            y_pred_proba = LabelCleanerMulticlassToBinary.convert_binary_proba_to_multiclass_proba(y_pred_proba)\n        if as_pandas:\n            if self.problem_type == MULTICLASS or (as_multiclass and self.problem_type == BINARY):\n                y_pred_proba = pd.DataFrame(data=y_pred_proba, columns=self.class_labels, index=X_index)\n            elif self.problem_type == QUANTILE:\n                y_pred_proba = pd.DataFrame(data=y_pred_proba, columns=self.quantile_levels, index=X_index)\n            else:\n                y_pred_proba = pd.Series(data=y_pred_proba, name=self.label, index=X_index)\n        return y_pred_proba\n\n    def predict(self, X: DataFrame, model=None, as_pandas=True, transform_features=True):\n        if as_pandas:\n            X_index = copy.deepcopy(X.index)\n        else:\n            X_index = None\n        y_pred_proba = self.predict_proba(X=X, model=model, as_pandas=False, as_multiclass=False, inverse_transform=False, transform_features=transform_features)\n        problem_type = self.label_cleaner.problem_type_transform or self.problem_type\n        y_pred = get_pred_from_proba(y_pred_proba=y_pred_proba, problem_type=problem_type)\n        if problem_type != QUANTILE:\n            y_pred = self.label_cleaner.inverse_transform(pd.Series(y_pred))\n            if as_pandas:\n                y_pred.index = X_index\n                y_pred.name = self.label\n            else:\n                y_pred = y_pred.values\n        else:\n            if as_pandas:\n                y_pred = pd.DataFrame(data=y_pred, columns=self.quantile_levels, index=X_index)\n        return y_pred\n\n    def _inverse_transform_proba(\n            self,\n            y_pred_proba,\n            as_pandas=True,\n            index=None,\n            as_multiclass=True,\n            inverse_transform=True):\n        """\n        Given internal prediction probabilities, convert them to external prediction probabilities.\n        """\n        if inverse_transform:\n            y_pred_proba = self.label_cleaner.inverse_transform_proba(y_pred_proba)\n        if as_multiclass and (self.problem_type == BINARY):\n            y_pred_proba = LabelCleanerMulticlassToBinary.convert_binary_proba_to_multiclass_proba(y_pred_proba)\n        if as_pandas:\n            if self.problem_type == MULTICLASS or (as_multiclass and self.problem_type == BINARY):\n                y_pred_proba = pd.DataFrame(data=y_pred_proba, columns=self.class_labels, index=index)\n            elif self.problem_type == QUANTILE:\n                y_pred_proba = pd.DataFrame(data=y_pred_proba, columns=self.quantile_levels, index=index)\n            else:\n                y_pred_proba = pd.Series(data=y_pred_proba, name=self.label, index=index)\n        return y_pred_proba\n\n    def predict_proba_multi(self,\n                            X: DataFrame = None,\n                            models: List[str] = None,\n                            as_pandas: bool = True,\n                            as_multiclass: bool = True,\n                            transform_features: bool = True,\n                            inverse_transform: bool = True,\n                            ) -> dict:\n        """\n        Returns a dictionary of prediction probabilities where the key is\n        the model name and the value is the model\'s prediction probabilities on the data.\n\n        Note that this will generally be much faster than calling `self.predict_proba` separately for each model\n        because this method leverages the model dependency graph to avoid redundant computation.\n\n        Parameters\n        ----------\n        X : DataFrame, default = None\n            The data to predict on.\n            If None:\n                If self.trainer.has_val, the validation data is used.\n                Else, the out-of-fold prediction probabilities are used.\n        models : List[str], default = None\n            The list of models to get predictions for.\n            If None, all models that can infer are used.\n        as_pandas : bool, default = True\n            Whether to return the output of each model as a pandas object (True) or numpy array (False).\n            Pandas object is a DataFrame if this is a multiclass problem or `as_multiclass=True`, otherwise it is a Series.\n            If the output is a DataFrame, the column order will be equivalent to `predictor.class_labels`.\n        as_multiclass : bool, default = True\n            Whether to return binary classification probabilities as if they were for multiclass classification.\n                Output will contain two columns, and if `as_pandas=True`, the column names will correspond to the binary class labels.\n                The columns will be the same order as `predictor.class_labels`.\n            If False, output will contain only 1 column for the positive class (get positive_class name via `predictor.positive_class`).\n            Only impacts output for binary classification problems.\n        transform_features : bool, default = True\n            If True, preprocesses data before predicting with models.\n            If False, skips global feature preprocessing.\n                This is useful to save on inference time if you have already called `data = predictor.transform_features(data)`.\n        inverse_transform : bool, default = True\n            If True, will return prediction probabilities in the original format.\n            If False (advanced), will return prediction probabilities in AutoGluon\'s internal format.\n\n        Returns\n        -------\n        Dictionary with model names as keys and model prediction probabilities as values.\n        """\n        trainer = self.load_trainer()\n\n        if models is None:\n            models = trainer.get_model_names(can_infer=True)\n        if X is not None and transform_features:\n            X = self.transform_features(X)\n        if X is None:\n            if not trainer.has_val:\n                X = trainer.load_X()\n                predict_proba_dict = dict()\n                for m in models:\n                    predict_proba_dict[m] = trainer.get_model_oof(m)\n            else:\n                X = trainer.load_X_val()\n                predict_proba_dict = trainer.get_model_pred_proba_dict(X=X, models=models, use_val_cache=True)\n        else:\n            predict_proba_dict = trainer.get_model_pred_proba_dict(X=X, models=models)\n\n        if inverse_transform:\n            # Inverse Transform labels\n            for m, pred_proba in predict_proba_dict.items():\n                predict_proba_dict[m] = self._inverse_transform_proba(y_pred_proba=pred_proba,\n                                                                      as_pandas=as_pandas,\n                                                                      as_multiclass=as_multiclass,\n                                                                      index=X.index,\n                                                                      inverse_transform=True)\n        return predict_proba_dict\n\n    def predict_multi(self,\n                      X: DataFrame = None,\n                      models: List[str] = None,\n                      as_pandas: bool = True,\n                      transform_features: bool = True,\n                      inverse_transform: bool = True) -> dict:\n        """\n        Identical to predict_proba_multi, except returns predictions instead of probabilities.\n        """\n        predict_proba_dict = self.predict_proba_multi(X=X,\n                                                      models=models,\n                                                      as_pandas=as_pandas,\n                                                      transform_features=transform_features,\n                                                      inverse_transform=inverse_transform)\n        predict_dict = {}\n        if as_pandas:\n            for m in predict_proba_dict:\n                predict_dict[m] = get_pred_from_proba_df(predict_proba_dict[m], problem_type=self.problem_type)\n        else:\n            for m in predict_proba_dict:\n                predict_dict[m] = get_pred_from_proba(predict_proba_dict[m], problem_type=self.problem_type)\n        return predict_dict\n\n\n    def _validate_fit_input(self, X: DataFrame, **kwargs):\n        if self.label not in X.columns:\n            raise KeyError(f"Label column \'{self.label}\' is missing from training data. Training data columns: {list(X.columns)}")\n        X_val = kwargs.get(\'X_val\', None)\n        self._validate_sample_weight(X, X_val)\n        self._validate_groups(X, X_val)\n\n    def _validate_sample_weight(self, X, X_val):\n        if self.sample_weight is not None:\n            if self.sample_weight in [AUTO_WEIGHT, BALANCE_WEIGHT]:\n                prefix = f"Using predefined sample weighting strategy: {self.sample_weight}."\n                if self.weight_evaluation:\n                    prefix += " Warning: We do not recommend weight_evaluation=True with predefined sample weighting."\n            else:\n                if self.sample_weight not in X.columns:\n                    raise KeyError(f"sample_weight column \'{self.sample_weight}\' is missing from training data. Training data columns: {list(X.columns)}")\n                weight_vals = X[self.sample_weight]\n                if weight_vals.isna().sum() > 0:\n                    raise ValueError(f"Sample weights in column \'{self.sample_weight}\' cannot be nan")\n                if weight_vals.dtype.kind not in \'biuf\':\n                    raise ValueError(f"Sample weights in column \'{self.sample_weight}\' must be numeric values")\n                if weight_vals.min() < 0:\n                    raise ValueError(f"Sample weights in column \'{self.sample_weight}\' must be nonnegative")\n                if self.weight_evaluation and X_val is not None and self.sample_weight not in X_val.columns:\n                    raise KeyError(f"sample_weight column \'{self.sample_weight}\' cannot be missing from validation data if weight_evaluation=True")\n                prefix = f"Values in column \'{self.sample_weight}\' used as sample weights instead of predictive features."\n            if self.weight_evaluation:\n                suffix = " Evaluation will report weighted metrics, so ensure same column exists in test data."\n            else:\n                suffix = " Evaluation metrics will ignore sample weights, specify weight_evaluation=True to instead report weighted metrics."\n            logger.log(20, prefix+suffix)\n\n    def _validate_groups(self, X, X_val):\n        if self.groups is not None:\n            if self.groups not in X.columns:\n                raise KeyError(f"groups column \'{self.groups}\' is missing from training data. Training data columns: {list(X.columns)}")\n            groups_vals = X[self.groups]\n            if len(groups_vals.unique()) < 2:\n                raise ValueError(f"Groups in column \'{self.groups}\' cannot have fewer than 2 unique values. Values: {list(groups_vals.unique())}")\n            if X_val is not None and self.groups in X_val.columns:\n                raise KeyError(f"groups column \'{self.groups}\' cannot be in validation data. Validation data columns: {list(X_val.columns)}")\n            logger.log(20, f"Values in column \'{self.groups}\' used as split folds instead of being automatically set. Bagged models will have {len(groups_vals.unique())} splits.")\n\n    def get_inputs_to_stacker(self, dataset=None, model=None, base_models: list = None, use_orig_features=True):\n        if model is not None or base_models is not None:\n            if model is not None and base_models is not None:\n                raise AssertionError(\'Only one of `model`, `base_models` is allowed to be set.\')\n\n        trainer = self.load_trainer()\n        if dataset is None:\n            if trainer.bagged_mode:\n                dataset_preprocessed = trainer.load_X()\n                fit = True\n            else:\n                dataset_preprocessed = trainer.load_X_val()\n                fit = False\n        else:\n            dataset_preprocessed = self.transform_features(dataset)\n            fit = False\n        if base_models is not None:\n            dataset_preprocessed = trainer.get_inputs_to_stacker(X=dataset_preprocessed, base_models=base_models, fit=fit, use_orig_features=use_orig_features)\n        elif model is not None:\n            base_models = list(trainer.model_graph.predecessors(model))\n            dataset_preprocessed = trainer.get_inputs_to_stacker(X=dataset_preprocessed, base_models=base_models, fit=fit, use_orig_features=use_orig_features)\n            # Note: Below doesn\'t quite work here because weighted_ensemble has unique input format returned that isn\'t a DataFrame.\n            # dataset_preprocessed = trainer.get_inputs_to_model(model=model_to_get_inputs_for, X=dataset_preprocessed, fit=fit)\n\n        return dataset_preprocessed\n\n    # Fits _FULL models and links them in the stack so _FULL models only use other _FULL models as input during stacking\n    # If model is specified, will fit all _FULL models that are ancestors of the provided model, automatically linking them.\n    # If no model is specified, all models are refit and linked appropriately.\n    def refit_ensemble_full(self, model=\'all\'):\n        return self.load_trainer().refit_ensemble_full(model=model)\n\n    def fit_transform_features(self, X, y=None, **kwargs):\n        if self.label in X:\n            X = X.drop(columns=[self.label])\n        if self.ignored_columns:\n            logger.log(20, f\'Dropping user-specified ignored columns: {self.ignored_columns}\')\n            X = X.drop(columns=self.ignored_columns, errors=\'ignore\')\n        for feature_generator in self.feature_generators:\n            X = feature_generator.fit_transform(X, y, **kwargs)\n        return X\n\n    def transform_features(self, X):\n        for feature_generator in self.feature_generators:\n            X = feature_generator.transform(X)\n        return X\n\n    def score(self, X: DataFrame, y=None, model=None):\n        if y is None:\n            X, y = self.extract_label(X)\n        self._validate_class_labels(y)\n        w = None\n        if self.weight_evaluation:\n            X, w = extract_column(X, self.sample_weight)\n        if self.eval_metric.needs_pred:\n            y_pred = self.predict(X=X, model=model, as_pandas=False)\n            if self.problem_type == BINARY:\n                # Use 1 and 0, otherwise f1 can crash due to unknown pos_label.\n                y_pred = self.label_cleaner.transform(y_pred)\n                y = self.label_cleaner.transform(y)\n        elif self.eval_metric.needs_quantile:\n            y_pred = self.predict(X=X, model=model, as_pandas=False)\n        else:\n            y_pred = self.predict_proba(X=X, model=model, as_pandas=False, as_multiclass=False)\n            y = self.label_cleaner.transform(y)\n        return compute_weighted_metric(y, y_pred, self.eval_metric, w, weight_evaluation=self.weight_evaluation, quantile_levels=self.quantile_levels)\n\n    # Scores both learner and all individual models, along with computing the optimal ensemble score + weights (oracle)\n    def score_debug(self, X: DataFrame, y=None, extra_info=False, compute_oracle=False, extra_metrics=None, skip_score=False, silent=False):\n        leaderboard_df = self.leaderboard(extra_info=extra_info, silent=silent)\n        if extra_metrics is None:\n            extra_metrics = []\n        if y is None:\n            error_if_missing = extra_metrics or not skip_score\n            X, y = self.extract_label(X, error_if_missing=error_if_missing)\n        w = None\n        if self.weight_evaluation:\n            X, w = extract_column(X, self.sample_weight)\n\n        X = self.transform_features(X)\n        if y is not None:\n            self._validate_class_labels(y)\n            y_internal = self.label_cleaner.transform(y)\n            y_internal = y_internal.fillna(-1)\n        else:\n            y_internal = None\n\n        trainer = self.load_trainer()\n        scores = {}\n        all_trained_models = trainer.get_model_names()\n        all_trained_models_can_infer = trainer.get_model_names(can_infer=True)\n        all_trained_models_original = all_trained_models.copy()\n        model_pred_proba_dict, pred_time_test_marginal = trainer.get_model_pred_proba_dict(X=X, models=all_trained_models_can_infer, record_pred_time=True)\n\n        if compute_oracle:\n            pred_probas = list(model_pred_proba_dict.values())\n            ensemble_selection = EnsembleSelection(ensemble_size=100, problem_type=trainer.problem_type, metric=self.eval_metric, quantile_levels=self.quantile_levels)\n            ensemble_selection.fit(predictions=pred_probas, labels=y_internal, identifiers=None, sample_weight=w)  # TODO: Only fit non-nan\n\n            oracle_weights = ensemble_selection.weights_\n            oracle_pred_time_start = time.time()\n            oracle_pred_proba_norm = [pred * weight for pred, weight in zip(pred_probas, oracle_weights)]\n            oracle_pred_proba_ensemble = np.sum(oracle_pred_proba_norm, axis=0)\n            oracle_pred_time = time.time() - oracle_pred_time_start\n            model_pred_proba_dict[\'OracleEnsemble\'] = oracle_pred_proba_ensemble\n            pred_time_test_marginal[\'OracleEnsemble\'] = oracle_pred_time\n            all_trained_models.append(\'OracleEnsemble\')\n\n        scoring_args = dict(\n            y=y,\n            y_internal=y_internal,\n            sample_weight=w\n        )\n\n        extra_scores = {}\n        for model_name, y_pred_proba_internal in model_pred_proba_dict.items():\n            if skip_score:\n                scores[model_name] = np.nan\n            else:\n                scores[model_name] = self._score_with_pred_proba(\n                    y_pred_proba_internal=y_pred_proba_internal,\n                    metric=self.eval_metric,\n                    **scoring_args\n                )\n            for metric in extra_metrics:\n                metric = get_metric(metric, self.problem_type, \'leaderboard_metric\')\n                if metric.name not in extra_scores:\n                    extra_scores[metric.name] = {}\n                extra_scores[metric.name][model_name] = self._score_with_pred_proba(\n                    y_pred_proba_internal=y_pred_proba_internal,\n                    metric=metric,\n                    **scoring_args\n                )\n\n        if extra_scores:\n            series = []\n            for metric in extra_scores:\n                series.append(pd.Series(extra_scores[metric], name=metric))\n            df_extra_scores = pd.concat(series, axis=1)\n            extra_metrics_names = list(df_extra_scores.columns)\n            df_extra_scores[\'model\'] = df_extra_scores.index\n            df_extra_scores = df_extra_scores.reset_index(drop=True)\n        else:\n            df_extra_scores = None\n            extra_metrics_names = None\n\n        pred_time_test = {}\n        # TODO: Add support for calculating pred_time_test_full for oracle_ensemble, need to copy graph from trainer and add oracle_ensemble to it with proper edges.\n        for model in model_pred_proba_dict.keys():\n            if model in all_trained_models_original:\n                base_model_set = trainer.get_minimum_model_set(model)\n                if len(base_model_set) == 1:\n                    pred_time_test[model] = pred_time_test_marginal[base_model_set[0]]\n                else:\n                    pred_time_test_full_num = 0\n                    for base_model in base_model_set:\n                        pred_time_test_full_num += pred_time_test_marginal[base_model]\n                    pred_time_test[model] = pred_time_test_full_num\n            else:\n                pred_time_test[model] = None\n\n        scored_models = list(scores.keys())\n        for model in all_trained_models:\n            if model not in scored_models:\n                scores[model] = None\n                pred_time_test[model] = None\n                pred_time_test_marginal[model] = None\n\n        logger.debug(\'Model scores:\')\n        logger.debug(str(scores))\n        model_names_final = list(scores.keys())\n        df = pd.DataFrame(\n            data={\n                \'model\': model_names_final,\n                \'score_test\': list(scores.values()),\n                \'pred_time_test\': [pred_time_test[model] for model in model_names_final],\n                \'pred_time_test_marginal\': [pred_time_test_marginal[model] for model in model_names_final],\n            }\n        )\n        if df_extra_scores is not None:\n            df = pd.merge(df, df_extra_scores, on=\'model\', how=\'left\')\n\n        df_merged = pd.merge(df, leaderboard_df, on=\'model\', how=\'left\')\n        df_merged = df_merged.sort_values(by=[\'score_test\', \'pred_time_test\', \'score_val\', \'pred_time_val\', \'model\'], ascending=[False, True, False, True, False]).reset_index(drop=True)\n        df_columns_lst = df_merged.columns.tolist()\n        explicit_order = [\n            \'model\',\n            \'score_test\',\n        ]\n        if extra_metrics_names is not None:\n            explicit_order += extra_metrics_names\n        explicit_order += [\n            \'score_val\',\n            \'pred_time_test\',\n            \'pred_time_val\',\n            \'fit_time\',\n            \'pred_time_test_marginal\',\n            \'pred_time_val_marginal\',\n            \'fit_time_marginal\',\n            \'stack_level\',\n            \'can_infer\',\n            \'fit_order\',\n        ]\n        df_columns_other = [column for column in df_columns_lst if column not in explicit_order]\n        df_columns_new = explicit_order + df_columns_other\n        df_merged = df_merged[df_columns_new]\n\n        return df_merged\n\n    def _score_with_pred_proba(self,\n                               y,\n                               y_internal,\n                               y_pred_proba_internal,\n                               metric,\n                               sample_weight=None,\n                               weight_evaluation=None):\n        metric = get_metric(metric, self.problem_type, \'leaderboard_metric\')\n        if weight_evaluation is None:\n            weight_evaluation = self.weight_evaluation\n        if metric.needs_pred:\n            if self.problem_type == BINARY:\n                # Use 1 and 0, otherwise f1 can crash due to unknown pos_label.\n                y_pred = get_pred_from_proba(y_pred_proba_internal, problem_type=self.problem_type)\n                y_tmp = y_internal\n            else:\n                y_pred = self.label_cleaner.inverse_transform_proba(y_pred_proba_internal, as_pred=True)\n                y_tmp = y\n        elif metric.needs_quantile:\n            y_pred = self.label_cleaner.inverse_transform_proba(y_pred_proba_internal, as_pred=True)\n            y_tmp = y\n        else:\n            y_pred = self.label_cleaner.inverse_transform_proba(y_pred_proba_internal, as_pred=False)\n            y_tmp = y_internal\n        return compute_weighted_metric(y_tmp, y_pred, metric, weights=sample_weight, weight_evaluation=weight_evaluation, quantile_levels=self.quantile_levels)\n\n    def _score_with_pred(self,\n                         y,\n                         y_internal,\n                         y_pred_internal,\n                         metric,\n                         sample_weight=None,\n                         weight_evaluation=None):\n        metric = get_metric(metric, self.problem_type, \'leaderboard_metric\')\n        if weight_evaluation is None:\n            weight_evaluation = self.weight_evaluation\n        if self.problem_type == BINARY:\n            # Use 1 and 0, otherwise f1 can crash due to unknown pos_label.\n            y_pred = y_pred_internal\n            y_tmp = y_internal\n        else:\n            y_pred = self.label_cleaner.inverse_transform(y_pred_internal)\n            y_tmp = y\n        return compute_weighted_metric(y_tmp, y_pred, metric, weights=sample_weight, weight_evaluation=weight_evaluation, quantile_levels=self.quantile_levels)\n\n    def _validate_class_labels(self, y: Series):\n        null_count = y.isnull().sum()\n        if null_count:\n            raise ValueError(f\'Labels cannot contain missing (nan) values. Found {null_count} missing label values.\')\n        if self.problem_type == MULTICLASS and not self.eval_metric.needs_pred:\n            y_unique = np.unique(y)\n            valid_class_set = set(self.class_labels)\n            unknown_classes = []\n            for cls in y_unique:\n                if cls not in valid_class_set:\n                    unknown_classes.append(cls)\n            if unknown_classes:\n                # log_loss / pac_score\n                raise ValueError(f\'Multiclass scoring with eval_metric=\\\'{self.eval_metric.name}\\\' does not support unknown classes. Unknown classes: {unknown_classes}\')\n\n    def evaluate_predictions(self, y_true, y_pred, sample_weight=None, silent=False, auxiliary_metrics=True, detailed_report=False):\n        """ Evaluate predictions. Does not support sample weights since this method reports a variety of metrics.\n            Args:\n                silent (bool): Should we print which metric is being used as well as performance.\n                auxiliary_metrics (bool): Should we compute other (problem_type specific) metrics in addition to the default metric?\n                detailed_report (bool): Should we computed more-detailed versions of the auxiliary_metrics? (requires auxiliary_metrics=True).\n\n            Returns single performance-value if auxiliary_metrics=False.\n            Otherwise returns dict where keys = metrics, values = performance along each metric.\n        """\n\n        is_proba = False\n        assert isinstance(y_true, (np.ndarray, pd.Series))\n        assert isinstance(y_pred, (np.ndarray, pd.Series, pd.DataFrame))\n        self._validate_class_labels(y_true)\n        if isinstance(y_pred, np.ndarray):\n            if self.problem_type == QUANTILE:\n                y_pred = pd.DataFrame(data=y_pred, columns=self.quantile_levels)\n            elif len(y_pred.shape) > 1:\n                y_pred = pd.DataFrame(data=y_pred, columns=self.class_labels)\n\n        if isinstance(y_pred, pd.DataFrame):\n            is_proba = True\n        elif not self.eval_metric.needs_pred:\n            raise AssertionError(f\'`evaluate_predictions` requires y_pred_proba input \'\n                                 f\'when evaluating "{self.eval_metric.name}"... Please generate valid input via `predictor.predict_proba(data)`.\\n\'\n                                 f\'This may have occurred if you passed in predict input instead of predict_proba input, \'\n                                 f\'or if you specified `as_multiclass=False` to `predictor.predict_proba(data, as_multiclass=False)`, \'\n                                 f\'which is not supported by `evaluate_predictions`.\')\n        if is_proba:\n            y_pred_proba = y_pred\n            y_pred = get_pred_from_proba_df(y_pred_proba, problem_type=self.problem_type)\n            if self.problem_type == BINARY:\n                # roc_auc crashes if this isn\'t done\n                y_pred_proba = y_pred_proba[self.positive_class]\n        else:\n            y_pred_proba = None\n            y_pred = pd.Series(y_pred)\n        if y_pred_proba is not None:\n            y_pred_proba_internal = self.label_cleaner.transform_proba(y_pred_proba, as_pandas=True)\n        else:\n            y_pred_proba_internal = None\n        y_true_internal = self.label_cleaner.transform(y_true)  # Get labels in numeric order\n        y_true_internal = y_true_internal.fillna(-1)\n        y_pred_internal = self.label_cleaner.transform(y_pred)  # Get labels in numeric order\n\n        # Compute auxiliary metrics:\n        auxiliary_metrics_lst = [self.eval_metric]\n        performance_dict = {}\n\n        if auxiliary_metrics:\n            if self.problem_type == REGRESSION:  # Adding regression metrics\n                auxiliary_metrics_lst += [\n                    \'root_mean_squared_error\',\n                    \'mean_squared_error\',\n                    \'mean_absolute_error\',\n                    \'r2\',\n                    \'pearsonr\',\n                    \'median_absolute_error\',\n                ]\n            if self.problem_type in [BINARY, MULTICLASS]:  # Adding classification metrics\n                auxiliary_metrics_lst += [\n                    \'accuracy\',\n                    \'balanced_accuracy\',\n                    # \'log_loss\',  # Don\'t include as it probably adds more confusion to novice users (can be infinite)\n                    \'mcc\',\n                ]\n            if self.problem_type == BINARY:  # binary-specific metrics\n                auxiliary_metrics_lst += [\n                    \'roc_auc\',\n                    \'f1\',\n                    \'precision\',\n                    \'recall\',\n                ]\n\n        scoring_args = dict(\n            y=y_true,\n            y_internal=y_true_internal,\n            weight_evaluation=False,\n        )\n\n        if sample_weight is not None:\n            scoring_args[\'sample_weight\'] = sample_weight\n            scoring_args[\'weight_evaluation\'] = True\n\n        for aux_metric in auxiliary_metrics_lst:\n            if isinstance(aux_metric, str):\n                aux_metric = get_metric(metric=aux_metric, problem_type=self.problem_type, metric_type=\'aux_metric\')\n            if not aux_metric.needs_pred and y_pred_proba_internal is None:\n                logger.log(15, f\'Skipping {aux_metric.name} because no prediction probabilities are available to score.\')\n                continue\n\n            if aux_metric.name not in performance_dict:\n                if y_pred_proba_internal is not None:\n                    score = self._score_with_pred_proba(\n                        y_pred_proba_internal=y_pred_proba_internal,\n                        metric=aux_metric,\n                        **scoring_args\n                    )\n                else:\n                    score = self._score_with_pred(\n                        y_pred_internal=y_pred_internal,\n                        metric=aux_metric,\n                        **scoring_args\n                    )\n                performance_dict[aux_metric.name] = score\n\n        if not silent:\n            if self.eval_metric.name in performance_dict:\n                score_eval = performance_dict[self.eval_metric.name]\n                logger.log(20, f"Evaluation: {self.eval_metric.name} on test data: {score_eval}")\n                if not self.eval_metric.greater_is_better_internal:\n                    logger.log(20, f"\\tNote: Scores are always higher_is_better. This metric score can be multiplied by -1 to get the metric value.")\n            logger.log(20, "Evaluations on test data:")\n            logger.log(20, json.dumps(performance_dict, indent=4))\n\n        if detailed_report and (self.problem_type != REGRESSION):\n            # Construct confusion matrix\n            try:\n                performance_dict[\'confusion_matrix\'] = confusion_matrix(y_true, y_pred, labels=self.label_cleaner.ordered_class_labels, output_format=\'pandas_dataframe\')\n            except ValueError:\n                pass\n            # One final set of metrics to report\n            cl_metric = lambda y_true, y_pred: classification_report(y_true, y_pred, output_dict=True)\n            metric_name = \'classification_report\'\n            if metric_name not in performance_dict:\n                try:  # only compute auxiliary metrics which do not error (y_pred = class-probabilities may cause some metrics to error)\n                    performance_dict[metric_name] = cl_metric(y_true, y_pred)\n                except ValueError:\n                    pass\n                if not silent and metric_name in performance_dict:\n                    logger.log(20, "Detailed (per-class) classification report:")\n                    logger.log(20, json.dumps(performance_dict[metric_name], indent=4))\n        return performance_dict\n\n    def extract_label(self, X, error_if_missing=True):\n        if self.label not in list(X.columns):\n            if error_if_missing:\n                raise ValueError(f"Provided DataFrame does not contain label column: {self.label}")\n            else:\n                return X, None\n        y = X[self.label].copy()\n        X = X.drop(self.label, axis=1)\n        return X, y\n\n    def leaderboard(self, X=None, y=None, extra_info=False, extra_metrics=None, only_pareto_frontier=False, skip_score=False, silent=False):\n        if X is not None:\n            leaderboard = self.score_debug(X=X, y=y, extra_info=extra_info, extra_metrics=extra_metrics, skip_score=skip_score, silent=True)\n        else:\n            if extra_metrics:\n                raise AssertionError(\'`extra_metrics` is only valid when data is specified.\')\n            trainer = self.load_trainer()\n            leaderboard = trainer.leaderboard(extra_info=extra_info)\n        if only_pareto_frontier:\n            if \'score_test\' in leaderboard.columns and \'pred_time_test\' in leaderboard.columns:\n                score_col = \'score_test\'\n                inference_time_col = \'pred_time_test\'\n            else:\n                score_col = \'score_val\'\n                inference_time_col = \'pred_time_val\'\n            leaderboard = get_leaderboard_pareto_frontier(leaderboard=leaderboard, score_col=score_col, inference_time_col=inference_time_col)\n        if not silent:\n            with pd.option_context(\'display.max_rows\', None, \'display.max_columns\', None, \'display.width\', 1000):\n                print(leaderboard)\n        return leaderboard\n\n    # TODO: cache_data must be set to True to be able to pass X and y as None in this function, otherwise it will error.\n    # Warning: This can take a very, very long time to compute if the data is large and the model is complex.\n    # A value of 0.01 means that the objective metric error would be expected to increase by 0.01 if the feature were removed.\n    # Negative values mean the feature is likely harmful.\n    # model: model (str) to get feature importances for, if None will choose best model.\n    # features: list of feature names that feature importances are calculated for and returned, specify None to get all feature importances.\n    # feature_stage: Whether to compute feature importance on raw original features (\'original\'), transformed features (\'transformed\') or on the features used by the particular model (\'transformed_model\').\n    def get_feature_importance(self, model=None, X=None, y=None, features: list = None, feature_stage=\'original\', subsample_size=5000, silent=False, **kwargs) -> DataFrame:\n        valid_feature_stages = [\'original\', \'transformed\', \'transformed_model\']\n        if feature_stage not in valid_feature_stages:\n            raise ValueError(f\'feature_stage must be one of: {valid_feature_stages}, but was {feature_stage}.\')\n        trainer = self.load_trainer()\n        if X is not None:\n            if y is None:\n                X, y = self.extract_label(X)\n            y = self.label_cleaner.transform(y)\n            X, y = self._remove_nan_label_rows(X, y)\n            if self.ignored_columns:\n                X = X.drop(columns=self.ignored_columns, errors=\'ignore\')\n            unused_features = [f for f in list(X.columns) if f not in self.features]\n            if len(unused_features) > 0:\n                logger.log(30, f\'These features in provided data are not utilized by the predictor and will be ignored: {unused_features}\')\n                X = X.drop(columns=unused_features)\n            \n            if feature_stage == \'original\':\n                return trainer._get_feature_importance_raw(model=model, X=X, y=y, features=features, subsample_size=subsample_size, transform_func=self.transform_features, silent=silent, **kwargs)\n            X = self.transform_features(X)\n        else:\n            if feature_stage == \'original\':\n                raise AssertionError(\'Feature importance `dataset` cannot be None if `feature_stage==\\\'original\\\'`. A test dataset must be specified.\')\n            y = None\n        raw = feature_stage == \'transformed\'\n        return trainer.get_feature_importance(X=X, y=y, model=model, features=features, raw=raw, subsample_size=subsample_size, silent=silent, **kwargs)\n\n    @staticmethod\n    def _remove_nan_label_rows(X, y):\n        if y.isnull().any():\n            y = y.dropna()\n            X = X.loc[y.index]\n        return X, y\n\n    def infer_problem_type(self, y: Series, silent=False):\n        problem_type = self._infer_problem_type(y, silent=silent)\n        if problem_type == QUANTILE:\n            if self.quantile_levels is None:\n                raise AssertionError(f\'problem_type is inferred to be {QUANTILE}, yet quantile_levels is not specified.\')\n        elif self.quantile_levels is not None:\n            if problem_type == REGRESSION:\n                problem_type = QUANTILE\n            else:\n                raise AssertionError(f"autogluon infers this to be classification problem (\'{problem_type}\'), yet quantile_levels is not None."\n                                     "If it is truly a quantile regression problem, "\n                                     f"please specify problem_type=\'{QUANTILE}\'.")\n        return problem_type\n\n    @staticmethod\n    def _infer_problem_type(y: Series, silent=False):\n        return infer_problem_type(y=y, silent=silent)\n\n    # Loads models in memory so that they don\'t have to be loaded during predictions\n    def persist_trainer(self, low_memory=False, models=\'all\', with_ancestors=False, max_memory=None) -> list:\n        self.trainer = self.load_trainer()\n        if not low_memory:\n            return self.trainer.persist_models(models, with_ancestors=with_ancestors, max_memory=max_memory)\n            # Warning: After calling this, it is not necessarily safe to save learner or trainer anymore\n            #  If neural network is persisted and then trainer or learner is saved, there will be an exception thrown\n        else:\n            return []\n\n    def distill(self, X=None, y=None, X_val=None, y_val=None, time_limit=None, hyperparameters=None, holdout_frac=None,\n                verbosity=None, models_name_suffix=None, teacher_preds=\'soft\',\n                augmentation_data=None, augment_method=\'spunge\', augment_args={\'size_factor\': 5, \'max_size\': int(1e5)}):\n        """ See abstract_trainer.distill() for details. """\n        if X is not None:\n            if (self.eval_metric is not None) and (self.eval_metric.name == \'log_loss\') and (self.problem_type == MULTICLASS):\n                X = augment_rare_classes(X, self.label, self.threshold)\n            if y is None:\n                X, y = self.extract_label(X)\n            X = self.transform_features(X)\n            y = self.label_cleaner.transform(y)\n            if self.problem_type == MULTICLASS:\n                y = y.fillna(-1)\n        else:\n            y = None\n\n        if X_val is not None:\n            if X is None:\n                raise ValueError("Cannot specify X_val without specifying X")\n            if y_val is None:\n                X_val, y_val = self.extract_label(X_val)\n            X_val = self.transform_features(X_val)\n            y_val = self.label_cleaner.transform(y_val)\n\n        if augmentation_data is not None:\n            augmentation_data = self.transform_features(augmentation_data)\n\n        trainer = self.load_trainer()\n        distilled_model_names = trainer.distill(X=X, y=y, X_val=X_val, y_val=y_val, time_limit=time_limit, hyperparameters=hyperparameters,\n                                                holdout_frac=holdout_frac, verbosity=verbosity, teacher_preds=teacher_preds, models_name_suffix=models_name_suffix,\n                                                augmentation_data=augmentation_data, augment_method=augment_method, augment_args=augment_args)\n        self.save_trainer(trainer=trainer)\n        return distilled_model_names\n\n    # TODO: Add data info gathering at beginning of .fit() that is used by all learners to add to get_info output\n    # TODO: Add feature inference / feature engineering info to get_info output\n    def get_info(self, **kwargs):\n        learner_info = {\n            \'path\': self.path,\n            \'label\': self.label,\n            \'random_state\': self.random_state,\n            \'version\': self.version,\n            \'features\': self.features,\n            \'feature_metadata_in\': self.feature_metadata_in,\n        }\n\n        return learner_info\n',
            'tabular/tests/unittests/test_tabular.py': '""" Runs autogluon.tabular on multiple benchmark datasets.\n    Run this benchmark with fast_benchmark=False to assess whether major chances make autogluon better or worse overall.\n    Lower performance-values = better, normalized to [0,1] for each dataset to enable cross-dataset comparisons.\n    Classification performance = error-rate, Regression performance = 1 - R^2\n\n    # TODO: assess that Autogluon correctly inferred the type of each feature (continuous vs categorical vs text)\n\n    # TODO: may want to take allowed run-time of AutoGluon into account? Eg. can produce performance vs training time curves for each dataset.\n\n    # TODO: We\'d like to add extra benchmark datasets with the following properties:\n    - parquet file format\n    - poker hand data: https://archive.ics.uci.edu/ml/datasets/Poker+Hand\n    - test dataset with just one data point\n    - test dataset where order of columns different than in training data (same column names)\n    - extreme-multiclass classification (500+ classes)\n    - high-dimensional features + low-sample size\n    - high levels of missingness in test data only, no missingness in train data\n    - classification w severe class imbalance\n    - regression with severely skewed Y-values (eg. predicting count data)\n    - text features in dataset\n"""\nimport os\nimport shutil\nimport warnings\nfrom random import seed\n\nimport numpy as np\nimport pandas as pd\nimport pytest\nimport tempfile\n\nfrom autogluon.common import space\nfrom autogluon.core.utils import download, unzip\nfrom autogluon.core.constants import BINARY, MULTICLASS, REGRESSION, QUANTILE, PROBLEM_TYPES_CLASSIFICATION\nfrom autogluon.tabular import TabularDataset, TabularPredictor\nfrom networkx.exception import NetworkXError\n\nPARALLEL_LOCAL_BAGGING = \'parallel_local\'\nSEQUENTIAL_LOCAL_BAGGING = \'sequential_local\'\n\ndef test_tabular():\n    ############ Benchmark options you can set: ########################\n    perf_threshold = 1.1 # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 0 # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = None\n    verbosity = 2 # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 100\n        time_limit = 60\n\n    fit_args = {\'verbosity\': verbosity}\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold, seed_val=seed_val, fit_args=fit_args)\n    run_tabular_benchmark_toy(fit_args=fit_args)\n\n\ndef _assert_predict_dict_identical_to_predict(predictor, data):\n    """Assert that predict_proba_dict and predict_dict are identical to looping calls to predict and predict_proba"""\n    predict_dict = predictor.predict_multi(data=data)\n    assert set(predictor.get_model_names()) == set(predict_dict.keys())\n    for m in predictor.get_model_names():\n        model_pred = predictor.predict(data, model=m)\n        assert model_pred.equals(predict_dict[m])\n\n    if predictor.can_predict_proba:\n        predict_proba_dict = predictor.predict_proba_multi(data=data)\n        assert set(predictor.get_model_names()) == set(predict_proba_dict.keys())\n        for m in predictor.get_model_names():\n            model_pred_proba = predictor.predict_proba(data, model=m)\n            assert model_pred_proba.equals(predict_proba_dict[m])\n\n\ndef test_advanced_functionality():\n    """\n    Tests a bunch of advanced functionality, including when used in combination.\n    The idea is that if this test passes, we are in good shape.\n    Simpler to test all of this within one test as it avoids repeating redundant setup such as fitting a predictor.\n    """\n    fast_benchmark = True\n    dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/AdultIncomeBinaryClassification.zip\',\n                      \'name\': \'AdultIncomeBinaryClassification\',\n                      \'problem_type\': BINARY}\n    label = \'class\'\n    directory_prefix = \'./datasets/\'\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file, name=dataset[\'name\'], url=dataset[\'url\'])\n    if fast_benchmark:  # subsample for fast_benchmark\n        subsample_size = 100\n        train_data = train_data.head(subsample_size)\n        test_data = test_data.head(subsample_size)\n    print(f"Evaluating Advanced Functionality on Benchmark Dataset {dataset[\'name\']}")\n    directory = directory_prefix + \'advanced/\' + dataset[\'name\'] + "/"\n    savedir = directory + \'AutogluonOutput/\'\n    shutil.rmtree(savedir, ignore_errors=True)  # Delete AutoGluon output directory to ensure previous runs\' information has been removed.\n    savedir_predictor_original = savedir + \'predictor/\'\n    predictor: TabularPredictor = TabularPredictor(label=label, path=savedir_predictor_original).fit(train_data)\n    leaderboard = predictor.leaderboard(data=test_data)\n    predictor.plot_ensemble_model()\n    extra_metrics = [\'accuracy\', \'roc_auc\', \'log_loss\']\n    test_data_no_label = test_data.drop(columns=[label])\n    with pytest.raises(ValueError):\n        # Error because skip_score is False and label not present\n        predictor.leaderboard(data=test_data_no_label)\n    with pytest.raises(ValueError):\n        # Error because extra_metrics != None and label not present\n        predictor.leaderboard(data=test_data_no_label, skip_score=True, extra_metrics=extra_metrics)\n    # Valid because skip_score=True\n    leaderboard_no_score = predictor.leaderboard(data=test_data.drop(columns=[label]), skip_score=True)\n    assert len(leaderboard) == len(leaderboard_no_score)\n    assert \'pred_time_test\' in leaderboard_no_score\n    assert \'pred_time_test_marginal\' in leaderboard_no_score\n    assert \'score_test\' in leaderboard_no_score\n    for i in range(len(leaderboard_no_score)):\n        # Assert that score_test is NaN for all models\n        assert leaderboard_no_score[\'score_test\'].isnull().iloc[i]\n    leaderboard_extra = predictor.leaderboard(data=test_data, extra_info=True, extra_metrics=extra_metrics)\n    _assert_predict_dict_identical_to_predict(predictor=predictor, data=test_data)\n    assert set(predictor.get_model_names()) == set(leaderboard[\'model\'])\n    assert set(predictor.get_model_names()) == set(leaderboard_extra[\'model\'])\n    assert set(leaderboard_extra.columns).issuperset(set(leaderboard.columns))\n    assert len(leaderboard) == len(leaderboard_extra)\n    assert set(leaderboard_extra.columns).issuperset(set(extra_metrics))  # Assert that extra_metrics are present in output\n    num_models = len(predictor.get_model_names())\n    feature_importances = predictor.feature_importance(data=test_data)\n    original_features = set(train_data.columns)\n    original_features.remove(label)\n    assert set(feature_importances.index) == original_features\n    assert set(feature_importances.columns) == {\'importance\', \'stddev\', \'p_value\', \'n\', \'p99_high\', \'p99_low\'}\n    predictor.transform_features()\n    test_data_transformed = predictor.transform_features(data=test_data)\n    predictor.info()\n\n    # Assert that transform_features=False works correctly\n    y_pred = predictor.predict(test_data)\n    y_pred_from_transform = predictor.predict(test_data_transformed, transform_features=False)\n    assert y_pred.equals(y_pred_from_transform)\n\n    y_pred_proba = None\n    if predictor.can_predict_proba:\n        y_pred_proba = predictor.predict_proba(test_data)\n        y_pred_proba_from_transform = predictor.predict_proba(test_data_transformed, transform_features=False)\n        assert y_pred_proba.equals(y_pred_proba_from_transform)\n\n    assert predictor.get_model_names_persisted() == []  # Assert that no models were persisted during training\n    assert predictor.unpersist_models() == []  # Assert that no models were unpersisted\n\n    persisted_models = predictor.persist_models(models=\'all\', max_memory=None)\n    assert set(predictor.get_model_names_persisted()) == set(persisted_models)  # Ensure all models are persisted\n    assert predictor.persist_models(models=\'all\', max_memory=None) == []  # Ensure that no additional models are persisted on repeated calls\n    unpersised_models = predictor.unpersist_models()\n    assert set(unpersised_models) == set(persisted_models)\n    assert predictor.get_model_names_persisted() == []  # Assert that all models were unpersisted\n\n    # Raise exception\n    with pytest.raises(NetworkXError):\n        predictor.persist_models(models=[\'UNKNOWN_MODEL_1\', \'UNKNOWN_MODEL_2\'])\n\n    assert predictor.get_model_names_persisted() == []\n\n    assert predictor.unpersist_models(models=[\'UNKNOWN_MODEL_1\', \'UNKNOWN_MODEL_2\']) == []\n\n    predictor.persist_models(models=\'all\', max_memory=None)\n    predictor.save()  # Save predictor while models are persisted: Intended functionality is that they won\'t be persisted when loaded.\n    predictor_loaded = TabularPredictor.load(predictor.path)  # Assert that predictor loading works\n    leaderboard_loaded = predictor_loaded.leaderboard(data=test_data)\n    assert len(leaderboard) == len(leaderboard_loaded)\n    assert predictor_loaded.get_model_names_persisted() == []  # Assert that models were not still persisted after loading predictor\n\n    _assert_predictor_size(predictor=predictor)\n    # Test cloning logic\n    with pytest.raises(AssertionError):\n        # Ensure don\'t overwrite existing predictor\n        predictor.clone(path=predictor.path)\n    path_clone = predictor.clone(path=predictor.path[:-1] + \'_clone\' + os.path.sep)\n    predictor_clone = TabularPredictor.load(path_clone)\n    assert predictor.path != predictor_clone.path\n    if predictor_clone.can_predict_proba:\n        y_pred_proba_clone = predictor_clone.predict_proba(test_data)\n        assert y_pred_proba.equals(y_pred_proba_clone)\n    y_pred_clone = predictor_clone.predict(test_data)\n    assert y_pred.equals(y_pred_clone)\n    leaderboard_clone = predictor_clone.leaderboard(data=test_data)\n    assert len(leaderboard) == len(leaderboard_clone)\n\n    # Test cloning for deployment logic\n    path_clone_for_deployment_og = predictor.path[:-1] + \'_clone_for_deployment\' + os.path.sep\n    with pytest.raises(FileNotFoundError):\n        # Assert that predictor does not exist originally\n        TabularPredictor.load(path_clone_for_deployment_og)\n    path_clone_for_deployment = predictor.clone_for_deployment(path=path_clone_for_deployment_og)\n    assert path_clone_for_deployment == path_clone_for_deployment_og\n    predictor_clone_for_deployment = TabularPredictor.load(path_clone_for_deployment)\n    assert predictor.path != predictor_clone_for_deployment.path\n    if predictor_clone_for_deployment.can_predict_proba:\n        y_pred_proba_clone_for_deployment = predictor_clone_for_deployment.predict_proba(test_data)\n        assert y_pred_proba.equals(y_pred_proba_clone_for_deployment)\n    y_pred_clone_for_deployment = predictor_clone_for_deployment.predict(test_data)\n    assert y_pred.equals(y_pred_clone_for_deployment)\n    leaderboard_clone_for_deployment = predictor_clone_for_deployment.leaderboard(data=test_data)\n    assert len(leaderboard) >= len(leaderboard_clone_for_deployment)\n    # Raise exception due to lacking fit artifacts\n    with pytest.raises(FileNotFoundError):\n        predictor_clone_for_deployment.refit_full()\n\n    assert(predictor.get_model_full_dict() == dict())\n    predictor.refit_full()\n    predictor.plot_ensemble_model()\n    assert(len(predictor.get_model_full_dict()) == num_models)\n    assert(len(predictor.get_model_names()) == num_models * 2)\n    for model in predictor.get_model_names():\n        predictor.predict(data=test_data, model=model)\n    predictor.refit_full()  # Confirm that refit_models aren\'t further refit.\n    assert(len(predictor.get_model_full_dict()) == num_models)\n    assert(len(predictor.get_model_names()) == num_models * 2)\n    predictor.delete_models(models_to_keep=[])  # Test that dry-run doesn\'t delete models\n    assert(len(predictor.get_model_names()) == num_models * 2)\n    predictor.predict(data=test_data)\n    predictor.delete_models(models_to_keep=[], dry_run=False)  # Test that dry-run deletes models\n    assert len(predictor.get_model_names()) == 0\n    assert len(predictor.leaderboard()) == 0\n    assert len(predictor.leaderboard(extra_info=True)) == 0\n    # Assert that predictor can no longer predict\n    try:\n        predictor.predict(data=test_data)\n    except:\n        pass\n    else:\n        raise AssertionError(\'predictor.predict should raise exception after all models are deleted\')\n    # Assert that clone is not impacted by changes to original\n    assert len(predictor_clone.leaderboard(data=test_data)) == len(leaderboard_clone)\n    if predictor_clone.can_predict_proba:\n        y_pred_proba_clone_2 = predictor_clone.predict_proba(data=test_data)\n        assert y_pred_proba.equals(y_pred_proba_clone_2)\n    y_pred_clone_2 = predictor_clone.predict(data=test_data)\n    assert y_pred.equals(y_pred_clone_2)\n    print(\'Tabular Advanced Functionality Test Succeeded.\')\n\n\ndef _assert_predictor_size(predictor: TabularPredictor):\n    predictor_size_disk = predictor.get_size_disk()\n    predictor_size_disk_per_file = predictor.get_size_disk_per_file()\n    assert predictor_size_disk > 0  # Assert that .get_size_disk() produces a >0 result and doesn\'t crash\n    assert len(predictor_size_disk_per_file) > 0\n    assert predictor_size_disk == predictor_size_disk_per_file.sum()\n\n\ndef test_advanced_functionality_bagging():\n    fast_benchmark = True\n    dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/AdultIncomeBinaryClassification.zip\',\n               \'name\': \'AdultIncomeBinaryClassification\',\n               \'problem_type\': BINARY}\n    label = \'class\'\n    directory_prefix = \'./datasets/\'\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file, name=dataset[\'name\'], url=dataset[\'url\'])\n    if fast_benchmark:  # subsample for fast_benchmark\n        subsample_size = 500\n        train_data = train_data.head(subsample_size)\n        test_data = test_data.head(subsample_size)\n    print(f"Evaluating Advanced Functionality (Bagging) on Benchmark Dataset {dataset[\'name\']}")\n    directory = directory_prefix + \'advanced/\' + dataset[\'name\'] + "/"\n    savedir = directory + \'AutogluonOutput/\'\n    shutil.rmtree(savedir, ignore_errors=True)  # Delete AutoGluon output directory to ensure previous runs\' information has been removed.\n    predictor = TabularPredictor(label=label, path=savedir).fit(\n        train_data,\n        num_bag_folds=2,\n        hyperparameters={\'GBM\': {}},\n    )\n\n    expected_num_models = 2\n    assert(len(predictor.get_model_names()) == expected_num_models)\n\n    _assert_predict_dict_identical_to_predict(predictor=predictor, data=test_data)\n\n    oof_pred_proba = predictor.get_oof_pred_proba()\n    assert(len(oof_pred_proba) == len(train_data))\n\n    predict_proba_dict_oof = predictor.predict_proba_multi()\n    for m in predictor.get_model_names():\n        predict_proba_oof = predictor.get_oof_pred_proba(model=m)\n        assert predict_proba_oof.equals(predict_proba_dict_oof[m])\n\n    score_oof = predictor.evaluate_predictions(train_data[label], oof_pred_proba)\n    model_best = predictor.get_model_best()\n\n    predictor.refit_full()\n    assert(len(predictor.get_model_full_dict()) == expected_num_models)\n    assert(len(predictor.get_model_names()) == expected_num_models * 2)\n\n    model_best_refit = predictor.get_model_best()\n    assert(model_best != model_best_refit)\n\n    # assert that refit model uses original model\'s OOF predictions\n    oof_pred_proba_refit = predictor.get_oof_pred_proba()\n    assert oof_pred_proba.equals(oof_pred_proba_refit)\n\n\ndef load_data(directory_prefix, train_file, test_file, name, url=None):\n    if not os.path.exists(directory_prefix):\n        os.mkdir(directory_prefix)\n    directory = directory_prefix + name + "/"\n    train_file_path = directory + train_file\n    test_file_path = directory + test_file\n    if (not os.path.exists(train_file_path)) or (not os.path.exists(test_file_path)):\n        # fetch files from s3:\n        print("%s data not found locally, so fetching from %s" % (name, url))\n        zip_name = download(url, directory_prefix)\n        unzip(zip_name, directory_prefix)\n        os.remove(zip_name)\n\n    train_data = TabularDataset(train_file_path)\n    test_data = TabularDataset(test_file_path)\n    return train_data, test_data\n\n\ndef run_tabular_benchmark_toy(fit_args):\n    dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/toyClassification.zip\',\n               \'name\': \'toyClassification\',\n               \'problem_type\': MULTICLASS,\n               \'label\': \'y\',\n               \'performance_val\': 0.436}\n    # 2-D toy noisy, imbalanced 4-class classification task with: feature missingness, out-of-vocabulary feature categories in test data, out-of-vocabulary labels in test data, training column missing from test data, extra distraction columns in test data\n    # toyclassif_dataset should produce 1 warning and 1 error during inference:\n    # Warning: Ignoring 181 (out of 1000) training examples for which the label value in column \'y\' is missing\n    # ValueError: Required columns are missing from the provided dataset. Missing columns: [\'lostcolumn\']\n\n    # Additional warning that would have occurred if ValueError was not triggered:\n    # UserWarning: These columns from this dataset were not present in the training dataset (AutoGluon will ignore them):  [\'distractioncolumn1\', \'distractioncolumn2\']\n\n    directory_prefix = \'./datasets/\'\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file, name=dataset[\'name\'], url=dataset[\'url\'])\n    print(f"Evaluating Benchmark Dataset {dataset[\'name\']}")\n    directory = directory_prefix + dataset[\'name\'] + "/"\n    savedir = directory + \'AutogluonOutput/\'\n    shutil.rmtree(savedir, ignore_errors=True)  # Delete AutoGluon output directory to ensure previous runs\' information has been removed.\n    predictor = TabularPredictor(label=dataset[\'label\'], path=savedir).fit(train_data, **fit_args)\n    assert len(predictor._trainer._models_failed_to_train) == 0\n    print(predictor.feature_metadata)\n    print(predictor.feature_metadata.type_map_raw)\n    print(predictor.feature_metadata.type_group_map_special)\n    try:\n        predictor.predict(test_data)\n    except KeyError:  # KeyError should be raised because test_data has missing column \'lostcolumn\'\n        pass\n    else:\n        raise AssertionError(f\'{dataset["name"]} should raise an exception.\')\n\n\ndef get_benchmark_sets():\n    # Information about each dataset in benchmark is stored in dict.\n    # performance_val = expected performance on this dataset (lower = better),should update based on previously run benchmarks\n    binary_dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/AdultIncomeBinaryClassification.zip\',\n                      \'name\': \'AdultIncomeBinaryClassification\',\n                      \'problem_type\': BINARY,\n                      \'label\': \'class\',\n                      \'performance_val\': 0.129}  # Mixed types of features.\n\n    multi_dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/CoverTypeMulticlassClassification.zip\',\n                     \'name\': \'CoverTypeMulticlassClassification\',\n                     \'problem_type\': MULTICLASS,\n                     \'label\': \'Cover_Type\',\n                     \'performance_val\': 0.032}  # big dataset with 7 classes, all features are numeric. Runs SLOW.\n\n    regression_dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/AmesHousingPriceRegression.zip\',\n                          \'name\': \'AmesHousingPriceRegression\',\n                          \'problem_type\': REGRESSION,\n                          \'label\': \'SalePrice\',\n                          \'performance_val\': 0.076}  # Regression with mixed feature-types, skewed Y-values.\n\n    toyregres_dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/toyRegression.zip\',\n                         \'name\': \'toyRegression\',\n                         \'problem_type\': REGRESSION,\n                         \'label\': \'y\',\n                         \'performance_val\': 0.183}\n    # 1-D toy deterministic regression task with: heavy label+feature missingness, extra distraction column in test data\n\n    # List containing dicts for each dataset to include in benchmark (try to order based on runtimes)\n    return [toyregres_dataset, binary_dataset, regression_dataset, multi_dataset]\n\n\ndef run_tabular_benchmarks(fast_benchmark, subsample_size, perf_threshold, seed_val, fit_args, dataset_indices=None, run_distill=False, crash_in_oof=False):\n    print("Running fit with args:")\n    print(fit_args)\n    # Each train/test dataset must be located in single directory with the given names.\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    EPS = 1e-10\n\n    # List containing dicts for each dataset to include in benchmark (try to order based on runtimes)\n    datasets = get_benchmark_sets()\n    if dataset_indices is not None: # only run some datasets\n        datasets = [datasets[i] for i in dataset_indices]\n\n    # Aggregate performance summaries obtained in previous benchmark run:\n    prev_perf_vals = [dataset[\'performance_val\'] for dataset in datasets]\n    previous_avg_performance = np.mean(prev_perf_vals)\n    previous_median_performance = np.median(prev_perf_vals)\n    previous_worst_performance = np.max(prev_perf_vals)\n\n    # Run benchmark:\n    performance_vals = [0.0] * len(datasets) # performance obtained in this run\n    directory_prefix = \'./datasets/\'\n    with warnings.catch_warnings(record=True) as caught_warnings:\n        for idx in range(len(datasets)):\n            dataset = datasets[idx]\n            train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file, name=dataset[\'name\'], url=dataset[\'url\'])\n            if seed_val is not None:\n                seed(seed_val)\n                np.random.seed(seed_val)\n            print("Evaluating Benchmark Dataset %s (%d of %d)" % (dataset[\'name\'], idx+1, len(datasets)))\n            directory = directory_prefix + dataset[\'name\'] + "/"\n            savedir = directory + \'AutogluonOutput/\'\n            shutil.rmtree(savedir, ignore_errors=True)  # Delete AutoGluon output directory to ensure previous runs\' information has been removed.\n            label = dataset[\'label\']\n            y_test = test_data[label]\n            test_data = test_data.drop(labels=[label], axis=1)\n            if fast_benchmark:\n                if subsample_size is None:\n                    raise ValueError("fast_benchmark specified without subsample_size")\n                if subsample_size < len(train_data):\n                    # .sample instead of .head to increase diversity and test cases where data index is not monotonically increasing.\n                    train_data = train_data.sample(n=subsample_size, random_state=seed_val)  # subsample for fast_benchmark\n            predictor = TabularPredictor(label=label, path=savedir).fit(train_data, **fit_args)\n            assert len(predictor._trainer._models_failed_to_train) == 0\n            results = predictor.fit_summary(verbosity=4)\n            original_features = list(train_data)\n            original_features.remove(label)\n            assert original_features == predictor.original_features\n            if predictor.problem_type != dataset[\'problem_type\']:\n                warnings.warn("For dataset %s: Autogluon inferred problem_type = %s, but should = %s" % (dataset[\'name\'], predictor.problem_type, dataset[\'problem_type\']))\n            predictor = TabularPredictor.load(savedir)  # Test loading previously-trained predictor from file\n            y_pred_empty = predictor.predict(test_data[0:0])\n            assert len(y_pred_empty) == 0\n            y_pred = predictor.predict(test_data)\n            perf_dict = predictor.evaluate_predictions(y_true=y_test, y_pred=y_pred, auxiliary_metrics=True)\n            if dataset[\'problem_type\'] != REGRESSION:\n                perf = 1.0 - perf_dict[\'accuracy\']  # convert accuracy to error-rate\n            else:\n                perf = 1.0 - perf_dict[\'r2\']  # unexplained variance score.\n            performance_vals[idx] = perf\n            print("Performance on dataset %s: %s   (previous perf=%s)" % (dataset[\'name\'], performance_vals[idx], dataset[\'performance_val\']))\n            if (not fast_benchmark) and (performance_vals[idx] > dataset[\'performance_val\'] * perf_threshold):\n                warnings.warn("Performance on dataset %s is %s times worse than previous performance." %\n                              (dataset[\'name\'], performance_vals[idx]/(EPS+dataset[\'performance_val\'])))\n            if predictor._trainer.bagged_mode and not crash_in_oof:\n                # TODO: Test index alignment with original training data (first handle duplicated rows / dropped rows edge cases)\n                y_pred_oof = predictor.get_oof_pred()\n                y_pred_proba_oof = predictor.get_oof_pred_proba(as_multiclass=False)\n                y_pred_oof_transformed = predictor.get_oof_pred(transformed=True)\n                y_pred_proba_oof_transformed = predictor.get_oof_pred_proba(as_multiclass=False, transformed=True)\n\n                # Assert expected type output\n                assert isinstance(y_pred_oof, pd.Series)\n                assert isinstance(y_pred_oof_transformed, pd.Series)\n                if predictor.problem_type == MULTICLASS:\n                    assert isinstance(y_pred_proba_oof, pd.DataFrame)\n                    assert isinstance(y_pred_proba_oof_transformed, pd.DataFrame)\n                else:\n                    if predictor.problem_type == BINARY:\n                        assert isinstance(predictor.get_oof_pred_proba(), pd.DataFrame)\n                    assert isinstance(y_pred_proba_oof, pd.Series)\n                    assert isinstance(y_pred_proba_oof_transformed, pd.Series)\n\n                assert y_pred_oof_transformed.equals(predictor.transform_labels(y_pred_oof, proba=False))\n\n                # Test that the transform_labels method is capable of reproducing the same output when converting back and forth, and test that oof \'transform\' parameter works properly.\n                y_pred_proba_oof_inverse = predictor.transform_labels(y_pred_proba_oof, proba=True)\n                y_pred_proba_oof_inverse_inverse = predictor.transform_labels(y_pred_proba_oof_inverse, proba=True, inverse=True)\n                y_pred_oof_inverse = predictor.transform_labels(y_pred_oof)\n                y_pred_oof_inverse_inverse = predictor.transform_labels(y_pred_oof_inverse, inverse=True)\n\n                if isinstance(y_pred_proba_oof_transformed, pd.DataFrame):\n                    pd.testing.assert_frame_equal(y_pred_proba_oof_transformed, y_pred_proba_oof_inverse)\n                    pd.testing.assert_frame_equal(y_pred_proba_oof, y_pred_proba_oof_inverse_inverse)\n                else:\n                    pd.testing.assert_series_equal(y_pred_proba_oof_transformed, y_pred_proba_oof_inverse)\n                    pd.testing.assert_series_equal(y_pred_proba_oof, y_pred_proba_oof_inverse_inverse)\n                pd.testing.assert_series_equal(y_pred_oof_transformed, y_pred_oof_inverse)\n                pd.testing.assert_series_equal(y_pred_oof, y_pred_oof_inverse_inverse)\n\n                # Test that index of both the internal training data and the oof outputs are consistent in their index values.\n                X_internal, y_internal = predictor.load_data_internal()\n                y_internal_index = list(y_internal.index)\n                assert list(X_internal.index) == y_internal_index\n                assert list(y_pred_oof.index) == y_internal_index\n                assert list(y_pred_proba_oof.index) == y_internal_index\n                assert list(y_pred_oof_transformed.index) == y_internal_index\n                assert list(y_pred_proba_oof_transformed.index) == y_internal_index\n            else:\n                # Raise exception\n                with pytest.raises(AssertionError):\n                    predictor.get_oof_pred()\n                with pytest.raises(AssertionError):\n                    predictor.get_oof_pred_proba()\n            if run_distill:\n                predictor.distill(time_limit=60, augment_args={\'size_factor\':0.5})\n\n    # Summarize:\n    avg_perf = np.mean(performance_vals)\n    median_perf = np.median(performance_vals)\n    worst_perf = np.max(performance_vals)\n    for idx in range(len(datasets)):\n        print("Performance on dataset %s: %s   (previous perf=%s)" % (datasets[idx][\'name\'], performance_vals[idx], datasets[idx][\'performance_val\']))\n\n    print("Average performance: %s" % avg_perf)\n    print("Median performance: %s" % median_perf)\n    print("Worst performance: %s" % worst_perf)\n\n    if not fast_benchmark:\n        if avg_perf > previous_avg_performance * perf_threshold:\n            warnings.warn("Average Performance is %s times worse than previously." % (avg_perf/(EPS+previous_avg_performance)))\n        if median_perf > previous_median_performance * perf_threshold:\n            warnings.warn("Median Performance is %s times worse than previously." % (median_perf/(EPS+previous_median_performance)))\n        if worst_perf > previous_worst_performance * perf_threshold:\n            warnings.warn("Worst Performance is %s times worse than previously." % (worst_perf/(EPS+previous_worst_performance)))\n\n    print("Ran fit with args:")\n    print(fit_args)\n    # List all warnings again to make sure they are seen:\n    print("\\n\\n WARNINGS:")\n    for w in caught_warnings:\n        warnings.warn(w.message)\n\n\ndef test_pseudolabeling():\n    datasets = get_benchmark_sets()\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    directory_prefix = \'./datasets/\'\n    hyperparam_setting = {\n        \'GBM\': {\'num_boost_round\': 10},\n        \'XGB\': {\'n_estimators\': 10},\n    }\n\n    fit_args = dict(\n        hyperparameters=hyperparam_setting,\n        time_limit=20,\n    )\n\n    fit_args_best = dict(\n        presets=\'best_quality\',\n        num_bag_folds=2,\n        num_bag_sets=1,\n        ag_args_ensemble=dict(fold_fitting_strategy=\'sequential_local\'),\n    )\n    for idx in range(len(datasets)):\n        dataset = datasets[idx]\n        label = dataset[\'label\']\n        problem_type = dataset[\'problem_type\']\n        name = dataset[\'name\']\n        train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file,\n                                          name=dataset[\'name\'], url=dataset[\'url\'])\n\n        print(f"Testing dataset with name: {name}, problem type: {problem_type}")\n\n        train_data = train_data.sample(50, random_state=1)\n        test_data = test_data[test_data[label].notna()]\n\n        if problem_type in PROBLEM_TYPES_CLASSIFICATION:\n            valid_class_idxes = test_data[label].isin(train_data[label].unique())\n            test_data = test_data[valid_class_idxes]\n\n        test_data = test_data.sample(50, random_state=1)\n\n        error_msg_og = f\'pseudolabel threw an exception during fit, it should have \' \\\n                       f\'succeeded on problem type:{problem_type} with dataset name:{name}, \' \\\n                       f\'with problem_type: {problem_type}. Under settings:\'\n\n        # Test label already given. If test label already given doesn\'t use pseudo labeling filter.\n        try:\n            print("Pseudolabel Testing: Pre-labeled data \'fit_pseudolabel\'")\n            _, y_pred_proba = TabularPredictor(label=label, problem_type=problem_type).fit_pseudolabel(\n                pseudo_data=test_data,\n                return_pred_prob=True,\n                train_data=train_data,\n                **fit_args,\n            )\n        except Exception as e:\n            assert False, error_msg_og + \'labeled test data\'\n\n        try:\n            print("Pseudolabel Testing: Pre-labeled data, best quality \'fit_pseudolabel\'")\n            _, y_pred_proba = TabularPredictor(label=label, problem_type=problem_type).fit_pseudolabel(\n                pseudo_data=test_data,\n                return_pred_prob=True,\n                train_data=train_data,\n                **fit_args_best,\n                **fit_args,\n            )\n        except Exception as e:\n            assert False, error_msg_og + \'labeled test data, best quality\'\n\n        # Test unlabeled pseudo data\n        unlabeled_test_data = test_data.drop(columns=label)\n        for flag_ensemble in [True, False]:\n            error_prefix = \'ensemble \' if flag_ensemble else \'\'\n            error_msg = error_prefix + error_msg_og\n            for is_weighted_ensemble in [True, False]:\n                error_suffix = \' with pseudo label model weighted ensembling\' if is_weighted_ensemble else \'\'\n\n                try:\n                    print("Pseudolabel Testing: Unlabeled data \'fit_pseudolabel\'")\n                    _, y_pred_proba = TabularPredictor(label=label, problem_type=problem_type).fit_pseudolabel(\n                        pseudo_data=unlabeled_test_data,\n                        return_pred_prob=True,\n                        train_data=train_data,\n                        use_ensemble=flag_ensemble,\n                        fit_ensemble=is_weighted_ensemble,\n                        **fit_args,\n                    )\n                except Exception as e:\n                    assert False, error_msg + \'unlabeled test data\' + error_suffix\n\n                try:\n                    print("Pseudolabel Testing: Unlabeled data, best quality \'fit_pseudolabel\'")\n                    _, y_pred_proba = TabularPredictor(label=label, problem_type=problem_type).fit_pseudolabel(\n                        pseudo_data=unlabeled_test_data,\n                        return_pred_prob=True,\n                        train_data=train_data,\n                        use_ensemble=flag_ensemble,\n                        fit_ensemble=is_weighted_ensemble,\n                        **fit_args_best,\n                        **fit_args,\n                    )\n                except Exception as e:\n                    assert False, error_msg + \'unlabeled test data, best quality\' + error_suffix\n\n\n@pytest.mark.slow\ndef test_tabularHPObagstack():\n    ############ Benchmark options you can set: ########################\n    perf_threshold = 1.1 # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 10000 # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = {\'scheduler\': \'local\', \'searcher\': \'auto\'}\n    num_stack_levels = 2\n    num_bag_folds = 2\n    verbosity = 2 # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 100\n        nn_options = {\'num_epochs\': 2, \'learning_rate\': space.Real(0.001, 0.01)}\n        gbm_options = {\'num_boost_round\': 20, \'learning_rate\': space.Real(0.01, 0.1)}\n        hyperparameters = {\'GBM\': gbm_options, \'NN_TORCH\': nn_options}\n        time_limit = 50\n\n    fit_args = {\n        \'num_bag_folds\': num_bag_folds,\n        \'num_stack_levels\': num_stack_levels,\n        \'verbosity\': verbosity,\n    }\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n        fit_args[\'num_bag_sets\'] = 2\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val=seed_val, fit_args=fit_args)\n\n\n\ndef test_tabularHPO():\n    ############ Benchmark options you can set: ########################\n    perf_threshold = 1.1 # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 99 # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = {\'scheduler\': \'local\', \'searcher\': \'auto\'}\n    verbosity = 2 # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 100\n        time_limit = 240\n        hyperparameter_tune_kwargs[\'num_trials\'] = 5\n\n    fit_args = {\'verbosity\': verbosity,}\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val=seed_val, fit_args=fit_args)\n\n\n@pytest.mark.slow\ndef test_tabular_feature_prune():\n    ############ Benchmark options you can set: ########################\n    perf_threshold = 1.1  # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 99  # random seed\n    subsample_size = None\n    ag_args = {\n        \'feature_prune_kwargs\': {\n            \'stop_threshold\': 3,\n            \'prune_ratio\': 0.05,\n            \'prune_threshold\': None,\n            \'n_train_subsample\': 1000,\n            \'n_fi_subsample\': 5000,\n            \'min_fi_samples\': 5000,\n            \'feature_prune_time_limit\': 10,\n            \'raise_exception\': True\n        }\n    }\n    verbosity = 2  # how much output to print\n    time_limit = None\n    fast_benchmark = True  # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 1000\n        gbm_options = {\'num_boost_round\': 20}\n        hyperparameters = {\'GBM\': gbm_options}\n        time_limit = 60\n\n    fit_args = {\'verbosity\': verbosity, }\n    fit_args[\'ag_args\'] = ag_args\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val=seed_val, fit_args=fit_args)\n\n\ndef _construct_tabular_bag_test_config(fold_fitting_strategy):\n    ############ Benchmark options you can set: ########################\n    num_bag_folds = 3\n    num_stack_levels = 0\n    perf_threshold = 1.1  # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 123  # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = None\n    verbosity = 2  # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True  # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 120\n        nn_options = {\'num_epochs\': 1}\n        gbm_options = {\'num_boost_round\': 30}\n        hyperparameters = {\'GBM\': gbm_options, \'NN_TORCH\': nn_options}\n        time_limit = 60\n\n    fit_args = {\n        \'num_bag_folds\': num_bag_folds,\n        \'num_stack_levels\': num_stack_levels,\n        \'verbosity\': verbosity,\n        \'ag_args_ensemble\': {\n            \'fold_fitting_strategy\': fold_fitting_strategy,\n        },\n    }\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n        fit_args[\'num_bag_sets\'] = 2\n    ###################################################################\n    config = dict(fast_benchmark=fast_benchmark, subsample_size=subsample_size,\n                  perf_threshold=perf_threshold, seed_val=seed_val, fit_args=fit_args)\n    return config\n\n\ndef test_tabular_parallel_local_bagging():\n    config = _construct_tabular_bag_test_config(PARALLEL_LOCAL_BAGGING)\n    run_tabular_benchmarks(**config)\n\n\ndef test_tabular_sequential_local_bagging():\n    config = _construct_tabular_bag_test_config(SEQUENTIAL_LOCAL_BAGGING)\n    run_tabular_benchmarks(**config)\n\n\ndef test_sample_weight():\n    dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/toyRegression.zip\',\n               \'name\': \'toyRegression\',\n               \'problem_type\': REGRESSION,\n               \'label\': \'y\',\n               \'performance_val\': 0.183}\n    directory_prefix = \'./datasets/\'\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file, name=dataset[\'name\'], url=dataset[\'url\'])\n    print(f"Evaluating Benchmark Dataset {dataset[\'name\']}")\n    directory = directory_prefix + dataset[\'name\'] + "/"\n    savedir = directory + \'AutogluonOutput/\'\n    shutil.rmtree(savedir, ignore_errors=True)  # Delete AutoGluon output directory to ensure previous runs\' information has been removed.\n    sample_weight = \'sample_weights\'\n    weights = np.abs(np.random.rand(len(train_data),))\n    test_weights = np.abs(np.random.rand(len(test_data),))\n    train_data[sample_weight] = weights\n    test_data_weighted = test_data.copy()\n    test_data_weighted[sample_weight] = test_weights\n    fit_args = {\'time_limit\': 20}\n    predictor = TabularPredictor(label=dataset[\'label\'], path=savedir, problem_type=dataset[\'problem_type\'], sample_weight=sample_weight).fit(train_data, **fit_args)\n    ldr = predictor.leaderboard(test_data)\n    perf = predictor.evaluate(test_data)\n    # Run again with weight_evaluation:\n    # FIXME: RMSE doesn\'t support sample_weight, this entire call doesn\'t make sense\n    predictor = TabularPredictor(label=dataset[\'label\'], path=savedir, problem_type=dataset[\'problem_type\'], sample_weight=sample_weight, weight_evaluation=True).fit(train_data, **fit_args)\n    # perf = predictor.evaluate(test_data_weighted)  # TODO: Doesn\'t work without implementing sample_weight in evaluate\n    predictor.distill(time_limit=10)\n    ldr = predictor.leaderboard(test_data_weighted)\n\n\ndef test_quantile():\n    quantile_levels = [0.01, 0.02, 0.05, 0.98, 0.99]\n    dataset = {\'url\': \'https://autogluon.s3.amazonaws.com/datasets/toyRegression.zip\',\n               \'name\': \'toyRegression\',\n               \'problem_type\': QUANTILE,\n               \'label\': \'y\'}\n    directory_prefix = \'./datasets/\'\n    train_file = \'train_data.csv\'\n    test_file = \'test_data.csv\'\n    train_data, test_data = load_data(directory_prefix=directory_prefix, train_file=train_file, test_file=test_file, name=dataset[\'name\'], url=dataset[\'url\'])\n    print(f"Evaluating Benchmark Dataset {dataset[\'name\']}")\n    directory = directory_prefix + dataset[\'name\'] + "/"\n    savedir = directory + \'AutogluonOutput/\'\n    shutil.rmtree(savedir, ignore_errors=True)  # Delete AutoGluon output directory to ensure previous runs\' information has been removed.\n    fit_args = {\'time_limit\': 20}\n    predictor = TabularPredictor(label=dataset[\'label\'], path=savedir, problem_type=dataset[\'problem_type\'],\n                                 quantile_levels=quantile_levels).fit(train_data, **fit_args)\n    ldr = predictor.leaderboard(test_data)\n    perf = predictor.evaluate(test_data)\n\n\n@pytest.mark.skip(reason="Ignored for now, since stacking is disabled without bagging.")\ndef test_tabular_stack1():\n    ############ Benchmark options you can set: ########################\n    num_stack_levels = 1\n    num_bag_folds = 0\n    perf_threshold = 1.1 # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 32 # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = None\n    verbosity = 2 # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 100\n        nn_options = {\'num_epochs\': 3}\n        gbm_options = {\'num_boost_round\': 30}\n        hyperparameters = {\'GBM\': gbm_options, \'NN_TORCH\': nn_options}\n        time_limit = 60\n\n    fit_args = {\n        \'num_bag_folds\': num_bag_folds,\n        \'num_stack_levels\': num_stack_levels,\n        \'verbosity\': verbosity,\n    }\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val = seed_val, fit_args=fit_args)\n\n\n@pytest.mark.skip(reason="Ignored for now, since stacking is disabled without bagging.")\ndef test_tabular_stack2():\n    ############ Benchmark options you can set: ########################\n    num_stack_levels = 2\n    num_bag_folds = 0\n    perf_threshold = 1.1 # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 66 # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = None\n    verbosity = 2 # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 100\n        nn_options = {\'num_epochs\': 3}\n        gbm_options = {\'num_boost_round\': 30}\n        hyperparameters = {\'GBM\': gbm_options, \'NN_TORCH\': nn_options}\n        time_limit = 60\n\n    fit_args = {\n        \'num_bag_folds\': num_bag_folds,\n        \'num_stack_levels\': num_stack_levels,\n        \'verbosity\': verbosity,\n    }\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val=seed_val, fit_args=fit_args)\n\n\n@pytest.mark.slow\ndef test_tabular_bagstack():\n    ############ Benchmark options you can set: ########################\n    num_stack_levels = 2\n    num_bag_folds = 3\n    perf_threshold = 1.1 # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 53 # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = None\n    verbosity = 2 # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 105\n        nn_options = {\'num_epochs\': 2}\n        gbm_options = [{\'num_boost_round\': 40}, \'GBMLarge\']\n        hyperparameters = {\'GBM\': gbm_options, \'NN_TORCH\': nn_options}\n        time_limit = 60\n\n    fit_args = {\n        \'num_bag_folds\': num_bag_folds,\n        \'num_stack_levels\': num_stack_levels,\n        \'verbosity\': verbosity,\n    }\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n        fit_args[\'num_bag_sets\'] = 2\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val=seed_val, fit_args=fit_args, run_distill=True)\n\n\n@pytest.mark.slow\ndef test_tabular_bagstack_use_bag_holdout():\n    ############ Benchmark options you can set: ########################\n    num_stack_levels = 2\n    num_bag_folds = 3\n    perf_threshold = 1.1  # How much worse can performance on each dataset be vs previous performance without warning\n    seed_val = 53  # random seed\n    subsample_size = None\n    hyperparameter_tune_kwargs = None\n    verbosity = 2  # how much output to print\n    hyperparameters = None\n    time_limit = None\n    fast_benchmark = True  # False\n    # If True, run a faster benchmark (subsample training sets, less epochs, etc),\n    # otherwise we run full benchmark with default AutoGluon settings.\n    # performance_value warnings are disabled when fast_benchmark = True.\n\n    #### If fast_benchmark = True, can control model training time here. Only used if fast_benchmark=True ####\n    if fast_benchmark:\n        subsample_size = 105\n        nn_options = {\'num_epochs\': 2}\n        gbm_options = [{\'num_boost_round\': 40}, \'GBMLarge\']\n        hyperparameters = {\'GBM\': gbm_options, \'NN_TORCH\': nn_options}\n        time_limit = 60\n\n    fit_args = {\n        \'num_bag_folds\': num_bag_folds,\n        \'num_stack_levels\': num_stack_levels,\n        \'verbosity\': verbosity,\n        \'use_bag_holdout\': True,\n    }\n    if hyperparameter_tune_kwargs is not None:\n        fit_args[\'hyperparameter_tune_kwargs\'] = hyperparameter_tune_kwargs\n    if hyperparameters is not None:\n        fit_args[\'hyperparameters\'] = hyperparameters\n    if time_limit is not None:\n        fit_args[\'time_limit\'] = time_limit\n        fit_args[\'num_bag_sets\'] = 2\n    ###################################################################\n    run_tabular_benchmarks(fast_benchmark=fast_benchmark, subsample_size=subsample_size, perf_threshold=perf_threshold,\n                           seed_val=seed_val, fit_args=fit_args, run_distill=True, crash_in_oof=True)\n\n\ndef test_tabular_raise_on_nonfinite_float_labels():\n    predictor = TabularPredictor(label=\'y\')\n    nonfinite_values = [np.nan, np.inf, np.NINF]\n\n    for idx, nonfinite_value in enumerate(nonfinite_values):\n        train_data = TabularDataset({\n            \'x\': [0.0, 1.0, 2.0, 3.0, 4.0],\n            \'y\': [0.0, 1.0, 2.0, 3.0, 4.0]\n            })\n        train_data.loc[idx, \'y\'] = nonfinite_value\n\n        with pytest.raises(ValueError) as ex_info:\n            predictor.fit(train_data)\n        assert str(ex_info.value).split()[-1] == str(idx)\n\ndef test_tabular_raise_on_nonfinite_class_labels():\n    predictor = TabularPredictor(label=\'y\')\n    nonfinite_values = [np.nan, np.inf, np.NINF]\n\n    for idx, nonfinite_value in enumerate(nonfinite_values):\n        train_data = TabularDataset({\n            \'x\': [0.0, 1.0, 2.0, 3.0, 4.0],\n            \'y\': ["a", "b", "c", "d", "e"]\n            })\n        train_data.loc[idx, \'y\'] = nonfinite_value\n\n        with pytest.raises(ValueError) as ex_info:\n            predictor.fit(train_data)\n        assert str(ex_info.value).split()[-1] == str(idx)\n\n\ndef test_tabular_log_to_file():\n    data_root = \'https://autogluon.s3.amazonaws.com/datasets/Inc/\'\n    train_data = TabularDataset(data_root + \'train.csv\')\n    train_data = train_data.sample(500)\n\n    predictor = TabularPredictor(label=\'class\', log_to_file=True).fit(\n        train_data=train_data,\n        hyperparameters={\n            "DUMMY": {}\n        }\n    )\n    log = TabularPredictor.load_log(predictor_path=predictor.path)\n    assert "TabularPredictor saved." in log[-1]\n    \n    with tempfile.TemporaryDirectory() as tempdir:\n        log_file = os.path.join(tempdir, "temp.log")\n        predictor = TabularPredictor(\n            label=\'class\',\n            log_to_file=True,\n            log_file_path=log_file\n        ).fit(\n            train_data=train_data,\n            hyperparameters={\n                "DUMMY": {}\n            }\n        )\n        log = TabularPredictor.load_log(log_file_path=log_file)\n        assert "TabularPredictor saved." in log[-1]\n    \n    with pytest.raises(AssertionError):\n        TabularPredictor.load_log()\n',
        }
